import { Node, Edge } from 'reactflow';

export enum NodeType {
  HTTP_REQUEST = 'httpRequest',
  WEBHOOK = 'webhook',
  DELAY = 'delay',
  IF_CONDITION = 'ifCondition',
  LOGGER = 'logger',
  DISCORD = 'discord',
  TELEGRAM = 'telegram',
  START = 'start'
}

export enum NodeStatus {
  IDLE = 'IDLE',
  RUNNING = 'RUNNING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR',
  RETRY = 'RETRY'
}

export interface NodeData {
  label: string;
  type: NodeType;
  status: NodeStatus;
  config: Record<string, any>;
  logs?: string[];
  [key: string]: any;
}

export type FlowNode = Node<NodeData>;
export type FlowEdge = Edge;

export interface FlowSchema {
  meta: {
    engine: string;
    created_by: string;
  };
  nodes: FlowNode[];
  edges: FlowEdge[];
}

export interface LogEntry {
  id: string;
  timestamp: string;
  nodeId: string;
  nodeLabel: string;
  level: 'INFO' | 'ERROR' | 'SUCCESS' | 'WARN';
  message: string;
}

export interface AIMessage {
  role: 'user' | 'ai' | 'system';
  content: string;
  timestamp: number;
  flowData?: FlowSchema; // Optional payload if AI generates a flow
}

export interface ExecutionContext {
  [nodeId: string]: any; // Output data from nodes
}

import { NodeType } from './types';

export const APP_NAME = "Flow Architect AI";
export const CREATOR_CREDIT = "Criado por João Layon";

export const INITIAL_NODES = [
  {
    id: 'start-1',
    type: 'custom',
    position: { x: 250, y: 50 },
    data: { 
      label: 'Start Trigger', 
      type: NodeType.START, 
      status: 'IDLE',
      config: {} 
    },
  },
];

export const SYSTEM_PROMPT = `
Você é o Flow Architect AI, criado por João Layon.
Você é um sistema composto por 3 Agentes Especialistas:

1. AGENTE CONSTRUTOR (Builder): Gera a estrutura JSON do fluxo.
2. AGENTE ARQUITETO TÉCNICO: Valida a lógica e conexões.
3. AGENTE DE SEGURANÇA: Garante que não haja vazamento de tokens e uso de APIs gratuitas.

Sua tarefa é converter a solicitação do usuário em um JSON de fluxo compatível com React Flow.

REGRAS:
- Retorne SEMPRE um JSON válido dentro de um bloco de código.
- O JSON deve seguir a interface FlowSchema.
- Nodes devem ter IDs únicos (ex: "node-1").
- Types suportados: "httpRequest", "webhook", "delay", "ifCondition", "logger", "discord", "telegram".
- Posicione os nodes (x, y) para que não fiquem sobrepostos (layout vertical ou horizontal organizado).
- "meta" deve conter: "created_by": "João Layon".

Estrutura de resposta desejada (Markdown):
Explicação breve do que foi criado (pelo Arquiteto Técnico).
\`\`\`json
{
  "meta": { "engine": "Flow Architect AI", "created_by": "João Layon" },
  "nodes": [ ... ],
  "edges": [ ... ]
}
\`\`\`
`;

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { FlowSchema } from '../types';

// Initialize Gemini Client
// IMPORTANT: process.env.API_KEY is required
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateFlowFromPrompt = async (userPrompt: string): Promise<{ text: string, flowData?: FlowSchema }> => {
  try {
    const model = 'gemini-2.5-flash-latest'; // Using Flash for speed/cost balance in automation tasks

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        { role: 'user', parts: [{ text: SYSTEM_PROMPT }] },
        { role: 'user', parts: [{ text: `Solicitação do usuário: ${userPrompt}` }] }
      ],
      config: {
        temperature: 0.2, // Low temperature for deterministic code generation
      }
    });

    const text = response.text || "Erro ao gerar resposta.";
    let flowData: FlowSchema | undefined;

    // Extract JSON block
    const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonMatch && jsonMatch[1]) {
      try {
        const parsed = JSON.parse(jsonMatch[1]);
        if (parsed.nodes && parsed.edges) {
          flowData = parsed as FlowSchema;
        }
      } catch (e) {
        console.error("Falha ao parsear JSON do fluxo gerado", e);
      }
    }

    return { text, flowData };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return { text: "Erro ao conectar com os agentes de IA. Verifique sua API Key.", flowData: undefined };
  }
};

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Simulated delay helper
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to generate log
const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    const { type, config, label } = node.data;
    this.updateNodeStatus(node.id, NodeStatus.RUNNING);
    this.addLog(createLog(node.id, label, 'INFO', `Iniciando execução...`));

    try {
      await wait(800); // Simulate processing time

      switch (type) {
        case NodeType.HTTP_REQUEST:
          // Simulate HTTP Request
          const method = config.method || 'GET';
          const url = config.url || 'https://api.exemplo.com/data';
          this.addLog(createLog(node.id, label, 'INFO', `${method} Request to ${url}`));

          // In a real backend, we would use fetch here. 
          // For demo, we simulate success unless configured to fail.
          this.context[node.id] = { status: 200, data: { mock: 'response' } };
          break;

        case NodeType.DELAY:
          const ms = config.ms || 2000;
          this.addLog(createLog(node.id, label, 'INFO', `Aguardando ${ms}ms...`));
          await wait(ms);
          break;

        case NodeType.LOGGER:
          this.addLog(createLog(node.id, label, 'SUCCESS', `LOG OUTPUT: ${JSON.stringify(this.context)}`));
          break;

        case NodeType.IF_CONDITION:
          // Simple logic simulation
          const condition = true; // Simplified for demo
          this.addLog(createLog(node.id, label, 'INFO', `Avaliando condição: ${condition}`));
          this.context[node.id] = condition;
          break;

        default:
          this.addLog(createLog(node.id, label, 'INFO', `Node genérico executado.`));
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      this.addLog(createLog(node.id, label, 'SUCCESS', `Node finalizado com sucesso.`));
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `Falha na execução: ${error.message}`));
      return false;
    }
  }

  public async run() {
    this.addLog(createLog('system', 'Engine', 'INFO', `Iniciando Flow Architect AI Engine. ${CREATOR_CREDIT}`));

    // Find start nodes (nodes with no incoming edges or specific Start type)
    // For simplicity, we assume topological sort or a simpler BFS traversal
    // This is a simplified BFS execution engine

    const queue: FlowNode[] = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) {
        // Fallback: pick the first node if no explicit trigger
        queue.push(this.nodes[0]);
    }

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        // Find next nodes
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
            queue.push(nextNode);
          }
        }
      } else {
        this.addLog(createLog('system', 'Engine', 'WARN', `Execução interrompida devido a erro no node ${currentNode.id}`));
        break; // Stop on error
      }
    }

    this.addLog(createLog('system', 'Engine', 'INFO', `Execução do fluxo finalizada.`));
  }
}

import React, { memo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
import { NodeStatus, NodeType } from '../types';

const statusColors = {
  [NodeStatus.IDLE]: 'border-gray-500 bg-gray-800',
  [NodeStatus.RUNNING]: 'border-blue-500 bg-blue-900 animate-pulse',
  [NodeStatus.SUCCESS]: 'border-green-500 bg-green-900',
  [NodeStatus.ERROR]: 'border-red-500 bg-red-900',
  [NodeStatus.RETRY]: 'border-yellow-500 bg-yellow-900',
};

const CustomNode = ({ data, isConnectable }: NodeProps) => {
  const statusClass = statusColors[data.status as NodeStatus] || statusColors[NodeStatus.IDLE];

  return (
    <div className={`px-4 py-2 shadow-lg rounded-md border-2 min-w-[150px] ${statusClass} transition-all duration-300`}>
      <div className="flex items-center">
        {/* Node Icon Identifier */}
        <div className="rounded-full w-3 h-3 bg-gray-400 mr-2"></div>
        <div className="flex flex-col">
          <div className="text-sm font-bold text-white">{data.label}</div>
          <div className="text-[10px] text-gray-300 uppercase tracking-wider">{data.type}</div>
        </div>
      </div>

      {/* Inputs (Top) */}
      <Handle
        type="target"
        position={Position.Top}
        isConnectable={isConnectable}
        className="w-3 h-3 bg-blue-400"
      />

      {/* Outputs (Bottom) */}
      <Handle
        type="source"
        position={Position.Bottom}
        isConnectable={isConnectable}
        className="w-3 h-3 bg-green-400"
      />

      {data.status === NodeStatus.RUNNING && (
        <div className="absolute -top-2 -right-2">
            <span className="relative flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
            </span>
        </div>
      )}
    </div>
  );
};

export default memo(CustomNode);

import React, { useState, useRef, useEffect } from 'react';
import { generateFlowFromPrompt } from '../services/geminiService';
import { AIMessage, FlowSchema } from '../types';
import { CREATOR_CREDIT } from '../constants';

interface AIChatProps {
  onImportFlow: (flowData: FlowSchema) => void;
}

const AIChat: React.FC<AIChatProps> = ({ onImportFlow }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<AIMessage[]>([
    { 
      role: 'system', 
      content: `Bem-vindo ao Flow Architect AI. Sou seu assistente de automação. ${CREATOR_CREDIT}.`, 
      timestamp: Date.now() 
    }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: AIMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const { text, flowData } = await generateFlowFromPrompt(input);

    const aiMsg: AIMessage = { 
      role: 'ai', 
      content: text, 
      timestamp: Date.now(),
      flowData 
    };

    setMessages(prev => [...prev, aiMsg]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-gray-900 border-l border-gray-700 w-96">
      <div className="p-4 border-b border-gray-700 bg-gray-800">
        <h2 className="text-lg font-bold text-white flex items-center gap-2">
          🤖 AI Architect
          <span className="text-xs bg-blue-600 px-2 py-0.5 rounded text-white">BETA</span>
        </h2>
        <p className="text-xs text-gray-400 mt-1">{CREATOR_CREDIT}</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[90%] rounded-lg p-3 text-sm ${
              msg.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gray-700 text-gray-200'
            }`}>
              {msg.role === 'ai' ? (
                // Simple markdown-ish rendering for AI text
                 <div dangerouslySetInnerHTML={{ __html: msg.content.replace(/\n/g, '<br/>').replace(/```json/g, '').replace(/```/g, '') }} />
              ) : (
                msg.content
              )}
            </div>

            {msg.flowData && (
              <button 
                onClick={() => onImportFlow(msg.flowData!)}
                className="mt-2 text-xs bg-green-600 hover:bg-green-700 text-white px-3 py-2 rounded flex items-center gap-2 transition-colors w-full justify-center shadow-lg border border-green-500"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                IMPORT_FLOW_FROM_AI()
              </button>
            )}
            <span className="text-[10px] text-gray-500 mt-1">
              {new Date(msg.timestamp).toLocaleTimeString()}
            </span>
          </div>
        ))}
        {loading && (
          <div className="flex items-start">
             <div className="bg-gray-700 rounded-lg p-3 text-sm text-gray-400 animate-pulse">
               Os arquitetos estão desenhando o fluxo...
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-gray-800 border-t border-gray-700">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ex: Crie um fluxo que lê um webhook e manda pro Discord..."
            className="flex-1 bg-gray-900 border border-gray-600 rounded px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500"
          />
          <button 
            onClick={handleSend}
            disabled={loading}
            className="bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 text-white p-2 rounded transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useEffect, useRef } from 'react';
import { LogEntry } from '../types';

interface LogPanelProps {
  logs: LogEntry[];
}

const LogPanel: React.FC<LogPanelProps> = ({ logs }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs]);

  const getLevelColor = (level: string) => {
    switch (level) {
      case 'ERROR': return 'text-red-400';
      case 'SUCCESS': return 'text-green-400';
      case 'WARN': return 'text-yellow-400';
      default: return 'text-blue-300';
    }
  };

  return (
    <div className="h-48 bg-gray-950 border-t border-gray-700 flex flex-col font-mono text-xs">
      <div className="flex items-center justify-between px-4 py-2 bg-gray-900 border-b border-gray-700">
        <h3 className="font-bold text-gray-300">Terminal de Execução</h3>
        <span className="text-gray-500">{logs.length} eventos</span>
      </div>
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-1">
        {logs.length === 0 && (
          <div className="text-gray-600 italic">Aguardando execução...</div>
        )}
        {logs.map((log) => (
          <div key={log.id} className="flex gap-3 hover:bg-gray-900 p-0.5 rounded">
            <span className="text-gray-500 shrink-0 w-20">{log.timestamp.split('T')[1].split('.')[0]}</span>
            <span className={`font-bold shrink-0 w-24 ${getLevelColor(log.level)}`}>[{log.level}]</span>
            <span className="text-purple-400 shrink-0 w-32 truncate" title={log.nodeId}>{log.nodeLabel}</span>
            <span className="text-gray-300 break-all">{log.message}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default LogPanel;

import React, { useCallback, useState, useMemo } from 'react';
import ReactFlow, {
  addEdge,
  Background,
  Controls,
  Connection,
  Edge,
  useNodesState,
  useEdgesState,
  Node,
} from 'reactflow';
import CustomNode from './components/CustomNode';
import AIChat from './components/AIChat';
import LogPanel from './components/LogPanel';
import { INITIAL_NODES, APP_NAME, CREATOR_CREDIT } from './constants';
import { FlowEngine } from './services/flowEngine';
import { FlowSchema, LogEntry, NodeStatus } from './types';

// Custom node types registry
const nodeTypes = {
  custom: CustomNode,
  httpRequest: CustomNode,
  webhook: CustomNode,
  delay: CustomNode,
  ifCondition: CustomNode,
  logger: CustomNode,
  discord: CustomNode,
  telegram: CustomNode,
  start: CustomNode
};

const App = () => {
  const [nodes, setNodes, onNodesChange] = useNodesState(INITIAL_NODES);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isExecuting, setIsExecuting] = useState(false);

  // Connect two nodes manually
  const onConnect = useCallback(
    (params: Connection) => setEdges((eds) => addEdge(params, eds)),
    [setEdges]
  );

  // ----------------------------------------------------
  // IMPORT_FLOW_FROM_AI Implementation
  // ----------------------------------------------------
  const handleImportFlow = useCallback((flowData: FlowSchema) => {
    console.log("IMPORT_FLOW_FROM_AI Triggered", flowData);

    // Map AI nodes to React Flow nodes with correct structure
    const newNodes: Node[] = flowData.nodes.map((n: any) => ({
      id: n.id,
      type: n.type || 'custom', // fallback
      position: n.position || { x: 0, y: 0 },
      data: { 
        ...n.data, 
        label: n.data?.label || n.type,
        status: NodeStatus.IDLE 
      }
    }));

    // Map AI edges
    const newEdges: Edge[] = flowData.edges.map((e: any) => ({
      id: e.id,
      source: e.source,
      target: e.target,
      animated: true,
      style: { stroke: '#63b3ed' }
    }));

    setNodes(newNodes);
    setEdges(newEdges);
    setLogs(prev => [
      ...prev, 
      { 
        id: Date.now().toString(), 
        timestamp: new Date().toISOString(), 
        level: 'SUCCESS', 
        message: 'Fluxo importado via AI Architect com sucesso.',
        nodeId: 'system',
        nodeLabel: 'System'
      }
    ]);
  }, [setNodes, setEdges]);

  // ----------------------------------------------------
  // EXECUTION ENGINE
  // ----------------------------------------------------
  const handleRunFlow = useCallback(async () => {
    if (isExecuting) return;
    setIsExecuting(true);
    setLogs([]); // Clear previous logs

    // Reset node statuses
    setNodes((nds) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));

    const engine = new FlowEngine(
      nodes, 
      edges, 
      setNodes, 
      (log: LogEntry) => setLogs(prev => [...prev, log])
    );

    await engine.run();
    setIsExecuting(false);
  }, [nodes, edges, isExecuting, setNodes]);

  return (
    <div className="flex h-screen w-screen overflow-hidden flex-col bg-gray-950 text-white">
      {/* HEADER */}
      <header className="h-14 bg-gray-900 border-b border-gray-700 flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-2">
          <div className="w-6 h-6 bg-gradient-to-br from-blue-500 to-purple-600 rounded-md"></div>
          <h1 className="font-bold text-lg tracking-tight">{APP_NAME}</h1>
        </div>

        <div className="flex items-center gap-4">
           {!process.env.API_KEY && (
             <span className="text-red-500 text-xs font-bold border border-red-500 px-2 py-1 rounded">MISSING API KEY</span>
           )}
           <button 
             onClick={handleRunFlow}
             disabled={isExecuting}
             className={`${isExecuting ? 'bg-gray-600 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700'} text-white px-6 py-1.5 rounded-md font-medium text-sm transition-all flex items-center gap-2 shadow-lg shadow-green-900/20`}
           >
             {isExecuting ? (
                <>
                  <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  Executando...
                </>
             ) : (
                <>
                  <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                  Executar Fluxo
                </>
             )}
           </button>
        </div>
      </header>

      {/* MAIN WORKSPACE */}
      <div className="flex-1 flex overflow-hidden">

        {/* REACT FLOW EDITOR */}
        <div className="flex-1 relative bg-gray-900">
          <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onConnect={onConnect}
            nodeTypes={nodeTypes}
            fitView
            proOptions={{ hideAttribution: true }}
          >
            <Background color="#4a5568" gap={16} />
            <Controls className="bg-gray-800 border-gray-600 fill-white text-white" />
          </ReactFlow>

          <div className="absolute bottom-4 left-4 text-[10px] text-gray-500 opacity-50 pointer-events-none">
            {CREATOR_CREDIT}
          </div>
        </div>

        {/* AI CHAT SIDEBAR */}
        <AIChat onImportFlow={handleImportFlow} />
      </div>

      {/* LOGS PANEL */}
