import React, { useState, useRef, useEffect } from 'react';
import { generateFlowFromPrompt } from '../services/geminiService';
import { AIMessage, FlowSchema } from '../types';
import { CREATOR_CREDIT } from '../constants';

interface AIChatProps {
  onImportFlow: (flowData: FlowSchema) => void;
  onCloseMobile?: () => void;
  isMobile?: boolean;
}

const AIChat: React.FC<AIChatProps> = ({ onImportFlow, onCloseMobile, isMobile }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<AIMessage[]>([
    { 
      role: 'system', 
      content: `Bem-vindo ao Flow Architect AI. Sou seu assistente de automação. ${CREATOR_CREDIT}.`, 
      timestamp: Date.now() 
    }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: AIMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const { text, flowData } = await generateFlowFromPrompt(input);

    const aiMsg: AIMessage = { 
      role: 'ai', 
      content: text, 
      timestamp: Date.now(),
      flowData 
    };

    setMessages(prev => [...prev, aiMsg]);
    setLoading(false);
  };

  return (
    <div className="flex flex-col h-full bg-gray-900 w-full">
      <div className="p-4 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
        <div>
            <h2 className="text-lg font-bold text-white flex items-center gap-2">
            🤖 AI Architect
            <span className="text-xs bg-blue-600 px-2 py-0.5 rounded text-white">BETA</span>
            </h2>
            <p className="text-xs text-gray-400 mt-1">{CREATOR_CREDIT}</p>
        </div>

        {isMobile && (
            <button 
                onClick={onCloseMobile}
                className="p-2 text-gray-400 hover:text-white bg-gray-700 rounded-full"
            >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        )}
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
            <div className={`max-w-[90%] rounded-lg p-3 text-sm ${
              msg.role === 'user' ? 'bg-blue-600 text-white' : 'bg-gray-700 text-gray-200'
            }`}>
              {msg.role === 'ai' ? (
                // Simple markdown-ish rendering for AI text
                 <div dangerouslySetInnerHTML={{ __html: msg.content.replace(/\n/g, '<br/>').replace(/```json/g, '').replace(/```/g, '') }} />
              ) : (
                msg.content
              )}
            </div>

            {msg.flowData && (
              <button 
                onClick={() => onImportFlow(msg.flowData!)}
                className="mt-2 text-xs bg-green-600 hover:bg-green-700 text-white px-3 py-2 rounded flex items-center gap-2 transition-colors w-full justify-center shadow-lg border border-green-500"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                IMPORT_FLOW_FROM_AI()
              </button>
            )}
            <span className="text-[10px] text-gray-500 mt-1">
              {new Date(msg.timestamp).toLocaleTimeString()}
            </span>
          </div>
        ))}
        {loading && (
          <div className="flex items-start">
             <div className="bg-gray-700 rounded-lg p-3 text-sm text-gray-400 animate-pulse">
               Os arquitetos estão desenhando o fluxo...
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-gray-800 border-t border-gray-700 safe-area-bottom">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Descreva o fluxo..."
            className="flex-1 bg-gray-900 border border-gray-600 rounded px-3 py-3 text-white text-sm focus:outline-none focus:border-blue-500"
          />
          <button 
            onClick={handleSend}
            disabled={loading}
            className="bg-blue-600 hover:bg-blue-700 disabled:bg-gray-600 text-white px-4 py-2 rounded transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React, { useEffect, useRef } from 'react';
import { LogEntry } from '../types';

interface LogPanelProps {
  logs: LogEntry[];
  isOpen?: boolean;
  onToggle?: () => void;
}

const LogPanel: React.FC<LogPanelProps> = ({ logs, isOpen = true, onToggle }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current && isOpen) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs, isOpen]);

  const getLevelColor = (level: string) => {
    switch (level) {
      case 'ERROR': return 'text-red-400';
      case 'SUCCESS': return 'text-green-400';
      case 'WARN': return 'text-yellow-400';
      default: return 'text-blue-300';
    }
  };

  return (
    <div className="h-full bg-gray-950 border-t border-gray-700 flex flex-col font-mono text-xs w-full">
      <div 
        className="flex items-center justify-between px-4 py-2 bg-gray-900 border-b border-gray-700 cursor-pointer hover:bg-gray-800 transition-colors"
        onClick={onToggle}
      >
        <div className="flex items-center gap-2">
            <span className={`transform transition-transform ${isOpen ? 'rotate-180' : ''}`}>
                <svg className="w-3 h-3 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" /></svg>
            </span>
            <h3 className="font-bold text-gray-300">Terminal de Execução</h3>
        </div>
        <span className="text-gray-500 bg-gray-800 px-2 py-0.5 rounded text-[10px]">{logs.length} eventos</span>
      </div>

      {isOpen && (
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-1">
            {logs.length === 0 && (
            <div className="text-gray-600 italic">Aguardando execução...</div>
            )}
            {logs.map((log) => (
            <div key={log.id} className="flex flex-wrap sm:flex-nowrap gap-x-3 gap-y-1 hover:bg-gray-900 p-0.5 rounded border-b border-gray-900/50">
                <span className="text-gray-500 shrink-0 w-16 sm:w-20 text-[10px] sm:text-xs pt-0.5">{log.timestamp.split('T')[1].split('.')[0]}</span>
                <span className={`font-bold shrink-0 w-16 sm:w-24 ${getLevelColor(log.level)}`}>[{log.level}]</span>
                <span className="text-purple-400 shrink-0 w-24 sm:w-32 truncate font-semibold" title={log.nodeId}>{log.nodeLabel}</span>
                <span className="text-gray-300 break-all">{log.message}</span>
            </div>
            ))}
        </div>
      )}
    </div>
  );
};

