              onEdgesChange={onEdgesChange}
              onConnect={onConnect}
              nodeTypes={nodeTypes}
              fitView
              proOptions={{ hideAttribution: true }}
              minZoom={0.5}
            >
              <Background color="#4a5568" gap={16} />
              <Controls className="bg-gray-800 border-gray-600 fill-white text-white" showInteractive={false} />
            </ReactFlow>

            <div className="absolute bottom-4 left-4 text-[10px] text-gray-500 opacity-50 pointer-events-none z-10">
              {CREATOR_CREDIT}
            </div>
          </div>

          {/* AI CHAT SIDEBAR (Drawer on mobile, Sidebar on desktop) */}
          <div className={`
            ${isMobile ? 'absolute inset-0 z-40 bg-gray-900' : 'relative w-96 border-l border-gray-700'}
            ${isMobile && activeTab === 'editor' ? 'hidden' : 'flex'}
            flex-col transition-all duration-300 ease-in-out
          `}>
             <AIChat 
                onImportFlow={handleImportFlow} 
                onCloseMobile={() => setActiveTab('editor')}
                isMobile={isMobile}
             />
          </div>
        </div>

        {/* BOTTOM PANEL (Logs & Files) */}
        <div className={`${isLogOpen ? 'h-52' : 'h-9'} transition-all duration-300 shrink-0 z-50 flex flex-col bg-gray-950 border-t border-gray-700`}>

          {/* Panel Header/Tabs */}
          <div 
            className="flex items-center justify-between px-4 py-0 bg-gray-900 border-b border-gray-700 h-9 shrink-0"
          >
            <div className="flex items-center h-full">
                <button 
                    onClick={() => { setIsLogOpen(true); setBottomPanelTab('logs'); }}
                    className={`h-full px-4 text-xs font-bold border-r border-gray-700 flex items-center gap-2 hover:bg-gray-800 transition-colors ${bottomPanelTab === 'logs' && isLogOpen ? 'text-blue-400 bg-gray-800' : 'text-gray-400'}`}
                >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 9l3 3-3 3m5 0h3M5 20h14a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    Terminal
                    <span className="bg-gray-700 text-gray-300 px-1.5 py-0.5 rounded-full text-[9px]">{logs.length}</span>
                </button>
                <button 
                    onClick={() => { setIsLogOpen(true); setBottomPanelTab('files'); }}
                    className={`h-full px-4 text-xs font-bold border-r border-gray-700 flex items-center gap-2 hover:bg-gray-800 transition-colors ${bottomPanelTab === 'files' && isLogOpen ? 'text-green-400 bg-gray-800' : 'text-gray-400'}`}
                >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                    Arquivos do Projeto
                    {files.length > 0 && <span className="bg-green-900 text-green-300 px-1.5 py-0.5 rounded-full text-[9px]">{files.length}</span>}
                </button>
            </div>

            <button onClick={() => setIsLogOpen(!isLogOpen)} className="text-gray-500 hover:text-white">
                <svg className={`w-4 h-4 transform transition-transform ${isLogOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </button>
          </div>

          {/* Panel Content */}
          {isLogOpen && (
            <div className="flex-1 overflow-hidden relative">
                <div className={`absolute inset-0 ${bottomPanelTab === 'logs' ? 'block' : 'hidden'}`}>
                    <LogPanel logs={logs} isOpen={true} />
                </div>
                <div className={`absolute inset-0 ${bottomPanelTab === 'files' ? 'block' : 'hidden'}`}>
                    <FilePanel files={files} isOpen={true} />
                </div>
            </div>
          )}
        </div>

        {/* SETTINGS MODAL */}
        <SettingsModal 
            isOpen={isSettingsOpen} 
            onClose={() => setIsSettingsOpen(false)} 
            apiKeyPresent={!!process.env.API_KEY}
        />
      </div>
    </ReactFlowProvider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { FlowNode, NodeType } from '../types';

interface NodeConfigPanelProps {
  node: FlowNode | null;
  isOpen: boolean;
  onClose: () => void;
  onUpdate: (nodeId: string, newConfig: any) => void;
}

const NodeConfigPanel: React.FC<NodeConfigPanelProps> = ({ node, isOpen, onClose, onUpdate }) => {
  const [config, setConfig] = useState<any>({});

  useEffect(() => {
    if (node) {
      setConfig(node.data.config || {});
    }
  }, [node]);

  if (!isOpen || !node) return null;

  const handleChange = (key: string, value: any) => {
    const newConfig = { ...config, [key]: value };
    setConfig(newConfig);
    // Auto-save on change (n8n style often has explicit save, but auto-update feels snappier here)
    onUpdate(node.id, newConfig);
  };

  const renderFields = () => {
    switch (node.data.type) {
      case NodeType.HTTP_REQUEST:
        return (
          <>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1">Request Method</label>
                <select 
                  value={config.method || 'GET'} 
                  onChange={(e) => handleChange('method', e.target.value)}
                  className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none"
                >
                  <option value="GET">GET</option>
                  <option value="POST">POST</option>
                  <option value="PUT">PUT</option>
                  <option value="DELETE">DELETE</option>
                  <option value="PATCH">PATCH</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1">URL</label>
                <input 
                  type="text" 
                  value={config.url || ''} 
                  onChange={(e) => handleChange('url', e.target.value)}
                  placeholder="https://api.example.com"
                  className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none font-mono"
                />
              </div>
              <div>
                 <label className="block text-xs font-bold text-gray-400 mb-1">Headers (JSON)</label>
                 <textarea
                    value={typeof config.headers === 'object' ? JSON.stringify(config.headers, null, 2) : config.headers || '{}'}
                    onChange={(e) => {
                        try {
                            const parsed = JSON.parse(e.target.value);
                            handleChange('headers', parsed);
                        } catch (err) {
                            // Allow typing invalid JSON temporarily
                        }
                    }}
                    className="w-full h-24 bg-gray-900 border border-gray-700 rounded p-2 text-xs text-white focus:border-blue-500 outline-none font-mono"
                 />
              </div>
            </div>
          </>
        );

      case NodeType.DELAY:
        return (
          <div>
            <label className="block text-xs font-bold text-gray-400 mb-1">Wait Time (ms)</label>
            <input 
              type="number" 
              value={config.ms || 1000} 
              onChange={(e) => handleChange('ms', parseInt(e.target.value))}
              className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none"
            />
            <p className="text-[10px] text-gray-500 mt-1">1000ms = 1 second</p>
          </div>
        );

      case NodeType.FILE_SAVE:
        return (
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-gray-400 mb-1">File Name</label>
              <input 
                type="text" 
                value={config.fileName || ''} 
                onChange={(e) => handleChange('fileName', e.target.value)}
                placeholder="data.txt"
                className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none font-mono"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-400 mb-1">File Format</label>
              <select 
                value={config.fileFormat || 'txt'} 
                onChange={(e) => handleChange('fileFormat', e.target.value)}
                className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none"
              >
                <option value="txt">Text (TXT)</option>
                <option value="json">JSON</option>
                <option value="csv">CSV</option>
              </select>
            </div>
          </div>
        );

      case NodeType.IF_CONDITION:
        return (
          <div>
            <label className="block text-xs font-bold text-gray-400 mb-1">Condition Expression</label>
            <input 
              type="text" 
              value={config.condition || ''} 
              onChange={(e) => handleChange('condition', e.target.value)}
              placeholder="value > 10"
              className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none font-mono"
            />
            <p className="text-[10px] text-gray-500 mt-1">Javascript expression logic</p>
          </div>
        );

      case NodeType.DISCORD:
      case NodeType.TELEGRAM:
      case NodeType.WEBHOOK:
         return (
             <div className="space-y-4">
                <div>
                    <label className="block text-xs font-bold text-gray-400 mb-1">Webhook URL</label>
                    <input 
                    type="text" 
                    value={config.url || ''} 
                    onChange={(e) => handleChange('url', e.target.value)}
                    className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none font-mono"
                    />
                </div>
                 <div>
                    <label className="block text-xs font-bold text-gray-400 mb-1">Payload / Message</label>
                    <input 
                    type="text" 
                    value={config.message || ''} 
                    onChange={(e) => handleChange('message', e.target.value)}
                    className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none"
                    />
                </div>
             </div>
         );

      default:
        return (
          <div className="text-gray-500 text-sm italic">
            Este node não possui configurações editáveis.
          </div>
        );
    }
  };

  return (
    <div className="absolute top-0 right-0 h-full w-full md:w-80 bg-gray-800 border-l border-gray-700 shadow-2xl z-20 flex flex-col animate-slide-in-right">
      <div className="flex items-center justify-between p-4 border-b border-gray-700 bg-gray-850">
        <div className="flex items-center gap-2">
            <div className={`w-3 h-3 rounded-full ${node.data.status === 'RUNNING' ? 'bg-blue-500' : 'bg-gray-500'}`}></div>
            <div>
                <h3 className="font-bold text-white text-sm">{node.data.label}</h3>
                <span className="text-[10px] text-gray-400 uppercase tracking-wider">{node.data.type}</span>
            </div>
        </div>
        <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4">
        <div className="mb-6">
            <h4 className="text-xs font-bold text-blue-400 uppercase tracking-widest mb-4 border-b border-gray-700 pb-2">Parâmetros</h4>
            {renderFields()}
        </div>

        <div className="bg-gray-900/50 rounded p-3 border border-gray-700/50">
            <h4 className="text-[10px] font-bold text-gray-500 uppercase mb-2">Node ID</h4>
            <code className="text-[10px] text-gray-400 font-mono select-all">{node.id}</code>
        </div>
      </div>

      <div className="p-4 border-t border-gray-700 bg-gray-850">
        <button 
            onClick={onClose}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-2 rounded text-sm transition-colors"
        >
            Concluir Edição
        </button>
      </div>
    </div>
  );
};

export default NodeConfigPanel;

import React, { useCallback, useState, useEffect } from 'react';
import ReactFlow, {
  addEdge,
  Background,
  Controls,
  Connection,
  Edge,
  useNodesState,
  useEdgesState,
  Node,
  ReactFlowProvider,
} from 'reactflow';
import CustomNode from './components/CustomNode';
import AIChat from './components/AIChat';
import LogPanel from './components/LogPanel';
import FilePanel from './components/FilePanel';
import SettingsModal from './components/SettingsModal';
import NodeConfigPanel from './components/NodeConfigPanel'; // Import Panel
import { INITIAL_NODES, APP_NAME, CREATOR_CREDIT } from './constants';
import { FlowEngine } from './services/flowEngine';
import { FlowSchema, LogEntry, NodeStatus, GeneratedFile, FlowNode } from './types';

// Custom node types registry
const nodeTypes = {
  custom: CustomNode,
  httpRequest: CustomNode,
  webhook: CustomNode,
  delay: CustomNode,
  ifCondition: CustomNode,
  logger: CustomNode,
  discord: CustomNode,
  telegram: CustomNode,
  fileSave: CustomNode,
  start: CustomNode
};

const App = () => {
  const [nodes, setNodes, onNodesChange] = useNodesState(INITIAL_NODES);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [files, setFiles] = useState<GeneratedFile[]>([]);
  const [isExecuting, setIsExecuting] = useState(false);

  // Selection State
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  // UI State for Responsiveness
  const [activeTab, setActiveTab] = useState<'editor' | 'chat'>('editor');
  const [bottomPanelTab, setBottomPanelTab] = useState<'logs' | 'files'>('logs');
  const [isLogOpen, setIsLogOpen] = useState(true);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Connect two nodes manually
  const onConnect = useCallback(
    (params: Connection) => setEdges((eds) => addEdge(params, eds)),
    [setEdges]
  );

  // Handle Node Selection
  const onNodeClick = useCallback((event: React.MouseEvent, node: Node) => {
    // If mobile and chat is open, maybe close chat? For now, standard behavior.
    setSelectedNodeId(node.id);
  }, []);

  // Handle Node Config Update
  const handleUpdateNodeConfig = useCallback((nodeId: string, newConfig: any) => {
    setNodes((nds) => 
      nds.map((node) => {
        if (node.id === nodeId) {
          return {
            ...node,
            data: {
              ...node.data,
              config: newConfig
            }
          };
        }
        return node;
      })
    );
  }, [setNodes]);

  // Find the selected node object
  const selectedNode = nodes.find(n => n.id === selectedNodeId) as FlowNode || null;

  // ----------------------------------------------------
  // IMPORT_FLOW_FROM_AI Implementation
  // ----------------------------------------------------
  const handleImportFlow = useCallback((flowData: FlowSchema) => {
    console.log("IMPORT_FLOW_FROM_AI Triggered", flowData);

    // Map AI nodes to React Flow nodes with correct structure
    const newNodes: Node[] = flowData.nodes.map((n: any) => ({
      id: n.id,
      type: n.type || 'custom', // fallback
      position: n.position || { x: 0, y: 0 },
      data: { 
        ...n.data, 
        label: n.data?.label || n.type,
        status: NodeStatus.IDLE 
      }
    }));

    // Map AI edges
    const newEdges: Edge[] = flowData.edges.map((e: any) => ({
      id: e.id,
      source: e.source,
      target: e.target,
      animated: true,
      style: { stroke: '#63b3ed' }
    }));

    setNodes(newNodes);
    setEdges(newEdges);
    setLogs(prev => [
      ...prev, 
      { 
        id: Date.now().toString(), 
        timestamp: new Date().toISOString(), 
        level: 'SUCCESS', 
        message: 'Fluxo importado via AI Architect com sucesso.',
        nodeId: 'system',
        nodeLabel: 'System'
      }
    ]);

    if (isMobile) {
      setActiveTab('editor');
    }
  }, [setNodes, setEdges, isMobile]);

  // ----------------------------------------------------
  // EXECUTION ENGINE
  // ----------------------------------------------------
  const handleRunFlow = useCallback(async () => {
    if (isExecuting) return;
    setIsExecuting(true);
    setLogs([]); 

    setIsLogOpen(true);
    setBottomPanelTab('logs');

    setNodes((nds) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));

    const engine = new FlowEngine(
      nodes, 
      edges, 
      setNodes, 
      (log: LogEntry) => setLogs(prev => [...prev, log]),
      (file: GeneratedFile) => {
          setFiles(prev => [file, ...prev]);
      }
    );

    await engine.run();
    setIsExecuting(false);
  }, [nodes, edges, isExecuting, setNodes]);

  return (
    <ReactFlowProvider>
      <div className="flex h-[100dvh] w-screen overflow-hidden flex-col bg-gray-950 text-white">
        {/* HEADER */}
        <header className="h-14 bg-gray-900 border-b border-gray-700 flex items-center justify-between px-4 shrink-0 z-50">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-gradient-to-br from-blue-500 to-purple-600 rounded-md"></div>
            <h1 className="font-bold text-lg tracking-tight hidden sm:block">{APP_NAME}</h1>
            <h1 className="font-bold text-lg tracking-tight sm:hidden">Flow AI</h1>
          </div>

          <div className="flex items-center gap-3">
             <div className="flex md:hidden bg-gray-800 rounded-lg p-1 mr-2">
                <button 
                  onClick={() => setActiveTab('editor')}
                  className={`px-3 py-1 rounded text-xs font-medium transition-colors ${activeTab === 'editor' ? 'bg-gray-600 text-white' : 'text-gray-400'}`}
                >
                  Editor
                </button>
                <button 
                  onClick={() => setActiveTab('chat')}
                  className={`px-3 py-1 rounded text-xs font-medium transition-colors ${activeTab === 'chat' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}
                >
                  IA Chat
                </button>
             </div>

             <button
               onClick={() => setIsSettingsOpen(true)}
               className="p-2 text-gray-400 hover:text-white bg-gray-800 hover:bg-gray-700 rounded-md transition-colors"
               title="Configurações"
             >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
             </button>

             <button 
               onClick={handleRunFlow}
               disabled={isExecuting}
               className={`${isExecuting ? 'bg-gray-600 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700'} text-white px-3 sm:px-6 py-1.5 rounded-md font-medium text-xs sm:text-sm transition-all flex items-center gap-2 shadow-lg shadow-green-900/20`}
             >
               {isExecuting ? (
                  <>
                    <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    <span className="hidden sm:inline">Executando...</span>
                  </>
               ) : (
                  <>
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                    <span className="hidden sm:inline">Executar</span>
                    <span className="sm:hidden">Run</span>
                  </>
               )}
             </button>
          </div>
        </header>

        {/* MAIN WORKSPACE */}
        <div className="flex-1 flex overflow-hidden relative">

          {/* REACT FLOW EDITOR */}
          <div className={`flex-1 relative bg-gray-900 h-full w-full ${isMobile && activeTab === 'chat' ? 'hidden' : 'block'}`}>
            <ReactFlow
              nodes={nodes}
              edges={edges}
              onNodesChange={onNodesChange}
              onEdgesChange={onEdgesChange}
              onConnect={onConnect}
              onNodeClick={onNodeClick} // Added click handler
              nodeTypes={nodeTypes}
              fitView
              proOptions={{ hideAttribution: true }}
              minZoom={0.5}
            >
              <Background color="#4a5568" gap={16} />
              <Controls className="bg-gray-800 border-gray-600 fill-white text-white" showInteractive={false} />
            </ReactFlow>

            <div className="absolute bottom-4 left-4 text-[10px] text-gray-500 opacity-50 pointer-events-none z-10">
              {CREATOR_CREDIT}
            </div>

            {/* NODE CONFIG PANEL (Overlays the editor on the right) */}
            <NodeConfigPanel 
                node={selectedNode}
                isOpen={!!selectedNode}
                onClose={() => setSelectedNodeId(null)}
                onUpdate={handleUpdateNodeConfig}
            />
          </div>

          {/* AI CHAT SIDEBAR */}
          <div className={`
            ${isMobile ? 'absolute inset-0 z-30 bg-gray-900' : 'relative w-96 border-l border-gray-700'}
            ${isMobile && activeTab === 'editor' ? 'hidden' : 'flex'}
            flex-col transition-all duration-300 ease-in-out
          `}>
             <AIChat 
                onImportFlow={handleImportFlow} 
                onCloseMobile={() => setActiveTab('editor')}
                isMobile={isMobile}
             />
          </div>
        </div>

        {/* BOTTOM PANEL (Logs & Files) */}
        <div className={`${isLogOpen ? 'h-52' : 'h-9'} transition-all duration-300 shrink-0 z-50 flex flex-col bg-gray-950 border-t border-gray-700`}>

          {/* Panel Header/Tabs */}
          <div 
            className="flex items-center justify-between px-4 py-0 bg-gray-900 border-b border-gray-700 h-9 shrink-0"
          >
            <div className="flex items-center h-full">
                <button 
                    onClick={() => { setIsLogOpen(true); setBottomPanelTab('logs'); }}
                    className={`h-full px-4 text-xs font-bold border-r border-gray-700 flex items-center gap-2 hover:bg-gray-800 transition-colors ${bottomPanelTab === 'logs' && isLogOpen ? 'text-blue-400 bg-gray-800' : 'text-gray-400'}`}
                >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 9l3 3-3 3m5 0h3M5 20h14a2 2 0 002-2V6a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    Terminal
                    <span className="bg-gray-700 text-gray-300 px-1.5 py-0.5 rounded-full text-[9px]">{logs.length}</span>
                </button>
                <button 
                    onClick={() => { setIsLogOpen(true); setBottomPanelTab('files'); }}
