import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Simulated delay helper
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to generate log
const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    const { type, config, label } = node.data;
    this.updateNodeStatus(node.id, NodeStatus.RUNNING);
    this.addLog(createLog(node.id, label, 'INFO', `Iniciando execução...`));

    try {
      await wait(800); // Simulate processing time

      switch (type) {
        case NodeType.HTTP_REQUEST:
          // Simulate HTTP Request
          const method = config.method || 'GET';
          const url = config.url || 'https://api.exemplo.com/data';
          this.addLog(createLog(node.id, label, 'INFO', `${method} Request to ${url}`));

          // MOCK: Smart mock for Currency API
          let responseData: any = { mock: 'data' };

          if (url.includes('USD-BRL') || url.includes('economia.awesomeapi')) {
             responseData = {
                USDBRL: {
                    code: "USD",
                    codein: "BRL",
                    name: "Dólar Americano/Real Brasileiro",
                    high: "5.55",
                    low: "5.48",
                    bid: "5.52",
                    ask: "5.53",
                    timestamp: Date.now().toString(),
                    create_date: new Date().toISOString()
                }
             };
             this.addLog(createLog(node.id, label, 'SUCCESS', `Cotação recebida: R$ ${responseData.USDBRL.bid}`));
          } else {
             responseData = { status: 200, message: "Mock data from external API", url };
          }

          // Save to context so next nodes can use it
          this.context[node.id] = responseData;
          break;

        case NodeType.DELAY:
          const ms = config.ms || 2000;
          this.addLog(createLog(node.id, label, 'INFO', `Aguardando ${ms}ms...`));
          await wait(ms);
          break;

        case NodeType.LOGGER:
          this.addLog(createLog(node.id, label, 'SUCCESS', `LOG OUTPUT: ${JSON.stringify(this.context)}`));
          break;

        case NodeType.FILE_SAVE:
          // Logic: Get data from previous node
          const incomingEdge = this.edges.find(e => e.target === node.id);
          let contentToSave = "No Input Data Found";

          if (incomingEdge && this.context[incomingEdge.source]) {
            const inputData = this.context[incomingEdge.source];

            // Format Content based on format
            if (config.fileFormat === 'json') {
                contentToSave = JSON.stringify(inputData, null, 2);
            } else if (config.fileFormat === 'csv') {
                // Simple CSV flattener mock
                contentToSave = `Key,Value\n${Object.entries(inputData).map(([k,v]) => `${k},${JSON.stringify(v)}`).join('\n')}`;
            } else {
                // TXT (Default) - Try to make it readable if it's the currency object
                if (inputData.USDBRL) {
                    contentToSave = `COTAÇÃO DÓLAR HOJE\n====================\n\nData: ${inputData.USDBRL.create_date}\nValor Compra: R$ ${inputData.USDBRL.bid}\nValor Venda: R$ ${inputData.USDBRL.ask}\nAlta: R$ ${inputData.USDBRL.high}\nBaixa: R$ ${inputData.USDBRL.low}\n`;
                } else {
                    contentToSave = typeof inputData === 'object' ? JSON.stringify(inputData, null, 2) : String(inputData);
                }
            }
          } else {
             this.addLog(createLog(node.id, label, 'WARN', `Nenhum dado de entrada encontrado vindo do node anterior. Verifique as conexões.`));
          }

          const fileName = config.fileName || `output-${Date.now()}.${config.fileFormat || 'txt'}`;

          if (this.onFileGenerated) {
              this.onFileGenerated({
                  id: Date.now().toString(),
                  name: fileName,
                  content: contentToSave,
                  extension: config.fileFormat || 'txt',
                  timestamp: Date.now(),
                  nodeId: node.id
              });
          }

          this.addLog(createLog(node.id, label, 'SUCCESS', `Arquivo "${fileName}" salvo em Arquivos do Projeto.`));
          break;

        case NodeType.IF_CONDITION:
          // Simple logic simulation
          const condition = true; // Simplified for demo
          this.addLog(createLog(node.id, label, 'INFO', `Avaliando condição: ${condition}`));
          this.context[node.id] = condition;
          break;

        default:
          this.addLog(createLog(node.id, label, 'INFO', `Node genérico executado.`));
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      this.addLog(createLog(node.id, label, 'SUCCESS', `Node finalizado com sucesso.`));
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `Falha na execução: ${error.message}`));
      return false;
    }
  }

  public async run() {
    this.addLog(createLog('system', 'Engine', 'INFO', `Iniciando Flow Architect AI Engine. ${CREATOR_CREDIT}`));
    this.context = {}; // Clear context

    // Find start nodes (nodes with no incoming edges or specific Start type)
    const queue: FlowNode[] = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) {
        // Fallback: pick the first node if no explicit trigger
        queue.push(this.nodes[0]);
    }

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        // Find next nodes
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
            queue.push(nextNode);
          }
        }
      } else {
        this.addLog(createLog('system', 'Engine', 'WARN', `Execução interrompida devido a erro no node ${currentNode.id}`));
        break; // Stop on error
      }
    }

    this.addLog(createLog('system', 'Engine', 'INFO', `Execução do fluxo finalizada.`));
  }
}

import React, { useState, useEffect } from 'react';
import { FlowNode, NodeType } from '../types';

interface NodeConfigPanelProps {
  node: FlowNode | null;
  isOpen: boolean;
  onClose: () => void;
  onUpdate: (nodeId: string, newConfig: any) => void;
}

const NodeConfigPanel: React.FC<NodeConfigPanelProps> = ({ node, isOpen, onClose, onUpdate }) => {
  const [config, setConfig] = useState<any>({});

  useEffect(() => {
    if (node) {
      setConfig(node.data.config || {});
    }
  }, [node]);

  if (!isOpen || !node) return null;

  const handleChange = (key: string, value: any) => {
    const newConfig = { ...config, [key]: value };
    setConfig(newConfig);
    // Auto-save on change (n8n style often has explicit save, but auto-update feels snappier here)
    onUpdate(node.id, newConfig);
  };

  const renderFields = () => {
    switch (node.data.type) {
      case NodeType.HTTP_REQUEST:
        return (
          <>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1">Request Method</label>
                <select 
                  value={config.method || 'GET'} 
                  onChange={(e) => handleChange('method', e.target.value)}
                  className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none"
                >
                  <option value="GET">GET</option>
                  <option value="POST">POST</option>
                  <option value="PUT">PUT</option>
                  <option value="DELETE">DELETE</option>
                  <option value="PATCH">PATCH</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1">URL</label>
                <input 
                  type="text" 
                  value={config.url || ''} 
                  onChange={(e) => handleChange('url', e.target.value)}
                  placeholder="https://api.example.com"
                  className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-sm text-white focus:border-blue-500 outline-none font-mono"
                />
              </div>
              <div>
                 <label className="block text-xs font-bold text-gray-400 mb-1">Headers (JSON)</label>
                 <textarea
                    value={typeof config.headers === 'object' ? JSON.stringify(config.headers, null, 2) : config.headers || '{}'}
                    onChange={(e) => {
                        try {
                            const parsed = JSON.parse(e.target.value);
                            handleChange('headers', parsed);
                        } catch (err) {
                            // Allow typing invalid JSON temporarily
                        }
                    }}
                    className="w-full h-24 bg-gray-900 border border-gray-700 rounded p-2 text-xs text-white focus:border-blue-500 outline-none font-mono"
                 />
              </div>
            </div>
