const STORAGE_KEY = 'flow_architect_projects_v1';

export const storageService = {
  getProjects: (): SavedProject[] => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      console.error("Erro ao ler projetos:", e);
      return [];
    }
  },

  saveProject: (name: string, nodes: FlowNode[], edges: FlowEdge[]): SavedProject => {
    const projects = storageService.getProjects();

    const newProject: SavedProject = {
      id: crypto.randomUUID(),
      name,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      nodes,
      edges
    };

    const updatedProjects = [newProject, ...projects];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedProjects));
    return newProject;
  },

  deleteProject: (id: string): void => {
    const projects = storageService.getProjects();
    const filtered = projects.filter(p => p.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
  },

  updateProject: (id: string, nodes: FlowNode[], edges: FlowEdge[]): void => {
    const projects = storageService.getProjects();
    const index = projects.findIndex(p => p.id === id);

    if (index !== -1) {
      projects[index] = {
        ...projects[index],
        nodes,
        edges,
        updatedAt: Date.now()
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  }
};

