        if (node.id === nodeId) {
          return {
            ...node,
            data: {
              ...node.data,
              config: newConfig
            }
          };
        }
        return node;
      })
    );
  }, [setNodes]);

  // Find the selected node object
  const selectedNode = nodes.find(n => n.id === selectedNodeId) as FlowNode || null;

  // ----------------------------------------------------
  // PROJECT MANAGEMENT (SAVE / LOAD)
  // ----------------------------------------------------

