    setNodes(project.nodes.map(n => ({...n, data: {...n.data, status: NodeStatus.IDLE}})));
    setEdges(project.edges);
    setLogs([{
        id: Date.now().toString(),
        timestamp: new Date().toISOString(),
        nodeId: 'system',
        nodeLabel: 'System',
        level: 'INFO',
        message: `Projeto "${project.name}" carregado.`
