      id: e.id,
      source: e.source,
      target: e.target,
      animated: true,
      style: { stroke: '#63b3ed' }
    }));

    setNodes(newNodes);
    setEdges(newEdges);
    setLogs(prev => [
      ...prev, 
      { 
        id: Date.now().toString(), 
