import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Simulated delay helper
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to generate log
const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  // Safe JSON Parser for config
  private parseConfigJSON(input: any): any {
      if (typeof input === 'object') return input;
      try {
          return JSON.parse(input);
      } catch (e) {
          return {};
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    const { type, config, label } = node.data;
    this.updateNodeStatus(node.id, NodeStatus.RUNNING);
    this.addLog(createLog(node.id, label, 'INFO', `Iniciando execução...`));

    try {
      await wait(500); // Small UI visual delay

      switch (type) {
        case NodeType.HTTP_REQUEST:
          const method = config.method || 'GET';
          const url = config.url || 'https://api.exemplo.com/data';

          this.addLog(createLog(node.id, label, 'INFO', `Request: ${method} ${url}`));

          // Tratamento de Mock vs Real
          let responseData: any;

          if (url.includes('USD-BRL') || url.includes('economia.awesomeapi')) {
             // MOCK para Dólar (AwesomeAPI)
             const bid = (5.40 + Math.random() * 0.20).toFixed(4);
             const ask = (parseFloat(bid) + 0.005).toFixed(4);
             responseData = {
                USDBRL: {
                    code: "USD",
                    codein: "BRL",
                    name: "Dólar Americano/Real Brasileiro",
                    high: (parseFloat(ask) + 0.05).toFixed(4),
                    low: (parseFloat(bid) - 0.05).toFixed(4),
                    varBid: "0.0005",
                    pctChange: "0.01",
                    bid: bid,
                    ask: ask,
                    timestamp: Date.now().toString(),
                    create_date: new Date().toISOString()
                }
             };
             this.addLog(createLog(node.id, label, 'SUCCESS', `[MOCK] AwesomeAPI respondeu com sucesso.`));
          } else {
             // Tentativa de Fetch Real
             this.addLog(createLog(node.id, label, 'INFO', `Tentando conexão real com a API...`));

             try {
                const headers = this.parseConfigJSON(config.headers);
                const body = (method === 'POST' || method === 'PUT') ? JSON.stringify(this.parseConfigJSON(config.body)) : undefined;

                this.addLog(createLog(node.id, label, 'INFO', `Payload enviado:\n${body || '(sem body)'}`));

                const response = await fetch(url, {
                    method,
                    headers: { 'Content-Type': 'application/json', ...headers },
                    body
                });

                if (!response.ok) throw new Error(`HTTP Error: ${response.status} ${response.statusText}`);

                const contentType = response.headers.get("content-type");
                if (contentType && contentType.indexOf("application/json") !== -1) {
                    responseData = await response.json();
                } else {
                    responseData = { text: await response.text() };
                }

                this.addLog(createLog(node.id, label, 'SUCCESS', `API Real respondeu: Status ${response.status}`));

             } catch (err: any) {
                 // Fallback para Mock se falhar (ex: CORS)
                 this.addLog(createLog(node.id, label, 'WARN', `Falha na requisição real (provavelmente CORS ou Network): ${err.message}`));
                 this.addLog(createLog(node.id, label, 'INFO', `Gerando resposta simulada para não travar o fluxo...`));
                 responseData = { 
                     status: 200, 
                     mocked: true, 
                     message: "Dados simulados pois a API real bloqueou o acesso via Browser (CORS).",
                     originalUrl: url 
                 };
             }
          }

          // Pretty Print JSON no Log
          this.addLog(createLog(node.id, label, 'INFO', `Output (JSON):\n${JSON.stringify(responseData, null, 2)}`));

          this.context[node.id] = responseData;
          break;

        case NodeType.DELAY:
          const ms = config.ms || 1000;
          this.addLog(createLog(node.id, label, 'INFO', `Aguardando ${ms}ms...`));
          await wait(ms);
          break;

        case NodeType.LOGGER:
          const prevNodeId = this.edges.find(e => e.target === node.id)?.source;
          const dataToLog = prevNodeId ? this.context[prevNodeId] : this.context;
          this.addLog(createLog(node.id, label, 'SUCCESS', `LOGGER OUTPUT:\n${JSON.stringify(dataToLog, null, 2)}`));
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          let contentToSave = "";
          const fileName = config.fileName || `output-${Date.now()}.${config.fileFormat || 'txt'}`;

          if (incomingEdge && this.context[incomingEdge.source]) {
            const inputData = this.context[incomingEdge.source];

            if (config.fileFormat === 'json') {
                contentToSave = JSON.stringify(inputData, null, 2);
            } else if (config.fileFormat === 'csv') {
                contentToSave = `Key,Value\n${Object.entries(inputData).map(([k,v]) => `${k},${JSON.stringify(v)}`).join('\n')}`;
            } else {
                // TXT Formatter
                if (inputData.USDBRL) {
                    contentToSave = `RELATÓRIO COTAÇÃO\n-----------------\nMoeda: ${inputData.USDBRL.name}\nCompra: R$ ${inputData.USDBRL.bid}\nVenda: R$ ${inputData.USDBRL.ask}\nData: ${new Date().toLocaleString()}`;
                } else {
                    contentToSave = typeof inputData === 'object' ? JSON.stringify(inputData, null, 2) : String(inputData);
                }
            }
          } else {
             contentToSave = "Sem dados de entrada.";
             this.addLog(createLog(node.id, label, 'WARN', `Sem dados do node anterior.`));
          }

          this.addLog(createLog(node.id, label, 'INFO', `Conteúdo do Arquivo Gerado:\n${contentToSave}`));

          if (this.onFileGenerated) {
              this.onFileGenerated({
                  id: Date.now().toString(),
                  name: fileName,
                  content: contentToSave,
                  extension: config.fileFormat || 'txt',
                  timestamp: Date.now(),
                  nodeId: node.id
              });
          }
          this.addLog(createLog(node.id, label, 'SUCCESS', `Arquivo "${fileName}" salvo.`));
          break;

        case NodeType.IF_CONDITION:
          // Avaliação segura da condição usando Function construtor (Sandbox simples)
          const conditionStr = config.condition || 'true';
          let result = false;

          // Pegar dados do input anterior para usar na condição
          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputData = edgeIn ? this.context[edgeIn.source] : {};

          try {
              // Cria uma função que recebe 'input' e retorna a avaliação
              // Ex: conditionStr = "input.value > 10"
              const checkCondition = new Function('input', `try { return ${conditionStr}; } catch(e) { return false; }`);
              result = checkCondition(inputData);
          } catch (e) {
              console.error(e);
              result = false;
          }

          this.addLog(createLog(node.id, label, 'INFO', `Condição: "${conditionStr}"`));
          this.addLog(createLog(node.id, label, 'INFO', `Input Data: ${JSON.stringify(inputData)}`));
          this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `Resultado: ${result}`));

          this.context[node.id] = result;
          // TODO: Implementar branching real nos edges baseada no resultado
          break;

        default:
          this.addLog(createLog(node.id, label, 'INFO', `Executado.`));
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `${error.message}`));
      return false;
    }
  }

  public async run() {
    this.addLog(createLog('system', 'Engine', 'INFO', `=== INICIANDO EXECUÇÃO ===`));
    this.context = {}; 

    const queue: FlowNode[] = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
            queue.push(nextNode);
          }
        }
      } else {
        break;
      }
    }
    this.addLog(createLog('system', 'Engine', 'INFO', `=== EXECUÇÃO FINALIZADA ===`));
  }
}

import React, { useEffect, useRef } from 'react';
import { LogEntry } from '../types';

interface LogPanelProps {
  logs: LogEntry[];
  isOpen?: boolean;
  onToggle?: () => void;
}

const LogPanel: React.FC<LogPanelProps> = ({ logs, isOpen = true, onToggle }) => {
