    if (scrollRef.current && isOpen) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [logs, isOpen]);

  const getLevelColor = (level: string) => {
    switch (level) {
      case 'ERROR': return 'text-red-400 border-red-900/50 bg-red-900/10';
      case 'SUCCESS': return 'text-green-400 border-green-900/50 bg-green-900/10';
      case 'WARN': return 'text-yellow-400 border-yellow-900/50 bg-yellow-900/10';
      default: return 'text-blue-300 border-blue-900/50 bg-blue-900/10';
    }
  };

  return (
    <div className="h-full bg-gray-950 border-t border-gray-700 flex flex-col font-mono text-xs w-full shadow-inner">
