      id: n.id,
      type: n.type || 'custom',
      position: n.position || { x: 0, y: 0 },
      data: { 
        ...n.data, 
        label: n.data?.label || n.type,
        status: NodeStatus.IDLE 
      }
    }));

    const newEdges: Edge[] = flowData.edges.map((e: any) => ({
      id: e.id,
      source: e.source,
      target: e.target,
      animated: true,
      style: { stroke: '#63b3ed' }
    }));

    setNodes(newNodes);
    setEdges(newEdges);

    setLogs(prev => [
      ...prev, 
      { 
        id: Date.now().toString(), 
        timestamp: new Date().toISOString(), 
        level: 'SUCCESS', 
        message: 'Fluxo importado via IA.',
        nodeId: 'system',
        nodeLabel: 'System'
      }
    ]);

    if (isMobile) {
      setActiveTab('editor');
    }
  }, [setNodes, setEdges, isMobile]);

