    if (isExecuting) return;
    setIsExecuting(true);
    setLogs([]); 
    setIsLogOpen(true);
    setBottomPanelTab('logs'); // Force switch to logs to see execution

    setNodes((nds) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));

    const engine = new FlowEngine(
      nodes, 
      edges, 
      setNodes, 
      (log: LogEntry) => setLogs(prev => [...prev, log]),
      (file: GeneratedFile) => {
          setFiles(prev => [file, ...prev]);
          // IMPORTANT: Do NOT switch to 'files' tab automatically here.
          // User wants to see the execution logs. We only update the state.
          // The log panel will contain a message saying the file was saved.
      }
    );

    await engine.run();
    setIsExecuting(false);
  }, [nodes, edges, isExecuting, setNodes]);

  return (
    <ReactFlowProvider>
      <div className="flex h-[100dvh] w-screen overflow-hidden flex-col bg-gray-950 text-white">
