          let responseData: any;

          // =================================================================
          // HANDLERS ESPECÍFICOS PARA APIS GRATUITAS (COM SIMULAÇÃO DE FALLBACK)
          // =================================================================

          // 1. COTAÇÃO (AwesomeAPI)
