PREÇO VENDA:  R$ ${inputData.USDBRL.ask}

Variação: ${inputData.USDBRL.pctChange}%
Máxima:   R$ ${inputData.USDBRL.high}
Mínima:   R$ ${inputData.USDBRL.low}
=========================================`;
                } else if (inputData.logradouro) {
                     contentToSave = `
=========================================
      CONSULTA DE CEP (VIACEP)
=========================================
CEP:        ${inputData.cep}
LOGRADOURO: ${inputData.logradouro}
BAIRRO:     ${inputData.bairro}
CIDADE/UF:  ${inputData.localidade} / ${inputData.uf}
=========================================`;
                } else {
                    contentToSave = typeof inputData === 'object' ? JSON.stringify(inputData, null, 2) : String(inputData);
                }
            }
          } else {
             contentToSave = "Nenhum dado recebido.";
          }

          if (this.onFileGenerated) {
              const newFile: GeneratedFile = {
                  id: crypto.randomUUID(),
                  name: fileName,
                  content: contentToSave,
                  extension: config?.fileFormat || 'txt',
                  timestamp: Date.now(),
                  nodeId: node.id
              };

              this.onFileGenerated(newFile);
              this.addLog(createLog(node.id, label, 'SUCCESS', `✅ ARQUIVO SALVO NA ABA 'ARQUIVOS'.`));
              this.addLog(createLog(node.id, label, 'INFO', `📄 CONTEÚDO:\n${contentToSave}\n`));
          }
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = false;
          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputCond = edgeIn ? this.context[edgeIn.source] : {};

          try {
              const checkCondition = new Function('input', `try { return ${conditionStr}; } catch(e) { return false; }`);
              result = checkCondition(inputCond);
          } catch (e) { result = false; }

          this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `Lógica (${conditionStr}) = ${result}`));
          this.context[node.id] = result;
          break;

        default:
          this.addLog(createLog(node.id, label, 'INFO', `OK.`));
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `ERRO FATAL: ${error.message}`));
      return false;
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO FLUXO (MODO API GRATUITA) ---`));
    this.context = {}; 

    const queue: FlowNode[] = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);

        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⛔ Fim do ramo (Condição Falsa).`));
             continue; 
        }

        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
            queue.push(nextNode);
          }
        }
      } else {
        this.addLog(createLog(currentNode.id, currentNode.data.label, 'ERROR', `🛑 Parada por erro.`));
        break;
      }
    }
    this.addLog(createLog('system', 'System', 'INFO', `🏁 --- EXECUÇÃO CONCLUÍDA ---`));
  }
}

import React from 'react';
import { GeneratedFile } from '../types';

interface FilePanelProps {
  files: GeneratedFile[];
  isOpen?: boolean;
}

const FilePanel: React.FC<FilePanelProps> = ({ files, isOpen = true }) => {

  const downloadFile = (file: GeneratedFile) => {
    // IMPORTANTE: Adiciona o Byte Order Mark (BOM) \uFEFF para forçar UTF-8 no Excel/Windows
    const byteOrderMark = '\uFEFF';

    let mimeType = 'text/plain;charset=utf-8';
    if (file.extension === 'json') mimeType = 'application/json;charset=utf-8';
    if (file.extension === 'csv') mimeType = 'text/csv;charset=utf-8';

    const blob = new Blob([byteOrderMark, file.content], { type: mimeType });

    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = file.name;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  if (!isOpen) return null;

  return (
    <div className="h-full bg-gray-950 flex flex-col font-mono text-xs w-full">
      <div className="flex-1 overflow-y-auto p-4 space-y-2">
        {files.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-gray-600 gap-2">
            <svg className="w-8 h-8 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
            <span className="italic">Nenhum arquivo gerado neste projeto.</span>
          </div>
        )}

        {files.map((file) => (
          <div key={file.id} className="flex items-center justify-between bg-gray-900 border border-gray-800 p-3 rounded-md hover:border-gray-700 transition-colors group">
             <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded bg-gray-800 flex items-center justify-center text-blue-400 font-bold uppercase text-[10px] border border-gray-700">
                    {file.extension}
                </div>
                <div className="flex flex-col">
                    <span className="text-gray-200 font-medium text-sm">{file.name}</span>
                    <span className="text-gray-500 text-[10px]">Gerado às {new Date(file.timestamp).toLocaleTimeString()} • UTF-8</span>
                </div>
             </div>

             <button 
                onClick={() => downloadFile(file)}
                className="text-gray-400 hover:text-white bg-gray-800 hover:bg-gray-700 p-2 rounded transition-colors border border-gray-700"
                title="Baixar Arquivo (UTF-8)"
             >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
             </button>
          </div>
        ))}
      </div>
    </div>
  );
};

