          }

          if (this.onFileGenerated) {
              const newFile: GeneratedFile = {
                  id: crypto.randomUUID(),
                  name: fileName,
                  content: contentToSave,
                  extension: config?.fileFormat || 'txt',
                  timestamp: Date.now(),
                  nodeId: node.id
              };

              this.onFileGenerated(newFile);
              this.addLog(createLog(node.id, label, 'SUCCESS', `✅ ARQUIVO SALVO COM UTF-8 (Compatível Excel/Windows)`));
              this.addLog(createLog(node.id, label, 'INFO', `📄 CONTEÚDO:\n${contentToSave}\n`));
          }
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = false;
          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputCond = edgeIn ? this.context[edgeIn.source] : {};

          try {
              const checkCondition = new Function('input', `try { return ${conditionStr}; } catch(e) { return false; }`);
              result = checkCondition(inputCond);
          } catch (e) { result = false; }

          this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `Lógica (${conditionStr}) = ${result}`));
          this.context[node.id] = result;
          break;

        default:
          this.addLog(createLog(node.id, label, 'INFO', `OK.`));
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `ERRO FATAL: ${error.message}`));
      return false;
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO FLUXO (MODO API GRATUITA) ---`));
    this.context = {}; 

    const queue: FlowNode[] = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);

        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⛔ Fim do ramo (Condição Falsa).`));
             continue; 
        }

        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
            queue.push(nextNode);
          }
        }
      } else {
        this.addLog(createLog(currentNode.id, currentNode.data.label, 'ERROR', `🛑 Parada por erro.`));
        break;
      }
    }
    this.addLog(createLog('system', 'System', 'INFO', `🏁 --- EXECUÇÃO CONCLUÍDA ---`));
  }
}

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Simulated delay helper
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper to generate log
const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  // Safe JSON Parser for config
  private parseConfigJSON(input: any): any {
      if (typeof input === 'object') return input;
      try {
          return JSON.parse(input);
      } catch (e) {
          return {};
      }
  }

  // --- FUNÇÃO AUXILIAR PARA FETCH COM RETRY VIA PROXY ---
  private async fetchRealData(url: string, options: any, nodeId: string, label: string): Promise<any> {
      try {
          // Tentativa 1: Direta
          const response = await fetch(url, options);
          if (!response.ok) throw new Error(`HTTP ${response.status}`);
          return await response.json();
      } catch (directError: any) {
          this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Acesso direto bloqueado (CORS). Ativando tunelamento via Proxy...`));

          try {
              // Tentativa 2: Via Proxy (AllOrigins) para burlar CORS e obter dados REAIS
              // Usamos 'raw' para obter o JSON limpo
              const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`;
              const proxyResponse = await fetch(proxyUrl, options);

              if (!proxyResponse.ok) throw new Error(`Proxy HTTP ${proxyResponse.status}`);

              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Conexão restabelecida via Proxy com sucesso!`));
              return await proxyResponse.json();

          } catch (proxyError: any) {
              // Se falhar no proxy, falha de verdade. Não inventamos dados.
              throw new Error(`Falha definitiva ao obter dados reais: ${proxyError.message}`);
          }
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    // FALLBACK DE SEGURANÇA: Se node.data.type estiver indefinido, tentamos usar node.type
    let { type, config, label } = node.data;
    if (!type && node.type) {
        type = node.type as NodeType;
        node.data.type = type; 
    }

    if (!label) label = type || 'Node';

    this.updateNodeStatus(node.id, NodeStatus.RUNNING);

    if (type !== NodeType.LOGGER) {
        this.addLog(createLog(node.id, label, 'INFO', `▶️ EXECUÇÃO INICIADA: ${type}`));
    }

    try {
      await wait(800); 

      switch (type) {
        case NodeType.HTTP_REQUEST:
          const method = config?.method || 'GET';
          const url = config?.url || 'https://api.exemplo.com/data';

          this.addLog(createLog(node.id, label, 'INFO', `📡 BUSCANDO DADOS REAIS: ${method} ${url}`));

          let responseData: any;

          // Configuração da Requisição
          const headers = this.parseConfigJSON(config?.headers);
          const body = (method === 'POST' || method === 'PUT') ? JSON.stringify(this.parseConfigJSON(config?.body)) : undefined;
          const options = {
              method,
              headers: { 'Content-Type': 'application/json', ...headers },
              body
          };

          // Executa a busca de dados reais (Direto ou Proxy)
          responseData = await this.fetchRealData(url, options, node.id, label);

          // --- FORMATAÇÃO VISUAL SE FOR COTAÇÃO ---
          if (responseData.USDBRL) {
             const bannerLog = `
╔══════════════════════════════════════════╗
║  💰 COTAÇÃO REAL (AWESOMEAPI)            ║
╠══════════════════════════════════════════╣
║  💵 BID (COMPRA): R$ ${responseData.USDBRL.bid}             ║
║  💵 ASK (VENDA):  R$ ${responseData.USDBRL.ask}             ║
╚══════════════════════════════════════════╝`;
             this.addLog(createLog(node.id, label, 'SUCCESS', bannerLog));
          }

          // --- LOG DO VIACEP ---
          else if (responseData.logradouro) {
             this.addLog(createLog(node.id, label, 'SUCCESS', `📍 ENDEREÇO REAL: ${responseData.logradouro}, ${responseData.localidade}/${responseData.uf}`));
          }

          else {
             this.addLog(createLog(node.id, label, 'SUCCESS', `✅ Dados reais recebidos com sucesso.`));
          }

          this.addLog(createLog(node.id, label, 'INFO', `📦 PAYLOAD RECEPTADO:\n${JSON.stringify(responseData, null, 2)}`));
          this.context[node.id] = responseData;
          break;

        case NodeType.DELAY:
          const ms = config?.ms || 1000;
          this.addLog(createLog(node.id, label, 'INFO', `⏳ Aguardando: ${ms}ms`));
          await wait(ms);
          break;

        case NodeType.LOGGER:
          const prevNodeIdLog = this.edges.find(e => e.target === node.id)?.source;
          const dataToLog = prevNodeIdLog ? this.context[prevNodeIdLog] : this.context;
          this.addLog(createLog(node.id, label, 'SUCCESS', `📝 LOG:\n${JSON.stringify(dataToLog, null, 2)}`));
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          let contentToSave = "";
          const fileName = config?.fileName || `output-${Date.now()}.${config?.fileFormat || 'txt'}`;

          this.addLog(createLog(node.id, label, 'INFO', `💾 GERANDO ARQUIVO (UTF-8): ${fileName}`));

          if (incomingEdge && this.context[incomingEdge.source]) {
            const inputData = this.context[incomingEdge.source];

            // --- FORMATAÇÃO INTELIGENTE ---
            if (config?.fileFormat === 'json') {
                contentToSave = JSON.stringify(inputData, null, 2);
            } 
            else if (config?.fileFormat === 'csv') {
                try {
                    const rows = [];
                    // Adaptador inteligente para Cotação
                    if (inputData.USDBRL) {
                        rows.push("Code,CodeIn,Bid,Ask,High,Low,Timestamp");
                        rows.push(`${inputData.USDBRL.code},${inputData.USDBRL.codein},${inputData.USDBRL.bid},${inputData.USDBRL.ask},${inputData.USDBRL.high},${inputData.USDBRL.low},${inputData.USDBRL.create_date}`);
                    } 
                    // Adaptador para ViaCEP
                    else if (inputData.cep) {
                        rows.push("CEP,Logradouro,Bairro,Cidade,UF");
                        rows.push(`${inputData.cep},${inputData.logradouro},${inputData.bairro},${inputData.localidade},${inputData.uf}`);
                    }
                    else {
                        rows.push("Key,Value");
                        Object.entries(inputData).forEach(([k, v]) => {
                            const val = typeof v === 'object' ? JSON.stringify(v) : v;
                            rows.push(`${k},${val}`);
                        });
                    }
                    contentToSave = rows.join('\n');
                } catch (e) {
                    contentToSave = JSON.stringify(inputData);
                }
            } 
            else {
                // TXT Formatter (Human Readable)
                if (inputData.USDBRL) {
                    contentToSave = `
=========================================
      RELATÓRIO FINANCEIRO (DADOS REAIS)
=========================================
FONTE: AWESOMEAPI (Via Proxy Seguro)
MOEDA: ${inputData.USDBRL.name}
DATA: ${new Date().toLocaleString()}

PREÇO COMPRA: R$ ${inputData.USDBRL.bid}
PREÇO VENDA:  R$ ${inputData.USDBRL.ask}

Variação: ${inputData.USDBRL.pctChange}%
Máxima:   R$ ${inputData.USDBRL.high}
Mínima:   R$ ${inputData.USDBRL.low}
=========================================`;
                } else if (inputData.logradouro) {
                     contentToSave = `
=========================================
      CONSULTA DE CEP (DADOS REAIS)
=========================================
CEP:        ${inputData.cep}
LOGRADOURO: ${inputData.logradouro}
BAIRRO:     ${inputData.bairro}
CIDADE/UF:  ${inputData.localidade} / ${inputData.uf}
=========================================`;
                } else {
                    contentToSave = typeof inputData === 'object' ? JSON.stringify(inputData, null, 2) : String(inputData);
                }
            }
          } else {
             contentToSave = "Nenhum dado recebido.";
          }

          if (this.onFileGenerated) {
              const newFile: GeneratedFile = {
                  id: crypto.randomUUID(),
                  name: fileName,
                  content: contentToSave,
                  extension: config?.fileFormat || 'txt',
                  timestamp: Date.now(),
                  nodeId: node.id
              };

              this.onFileGenerated(newFile);
              this.addLog(createLog(node.id, label, 'SUCCESS', `✅ ARQUIVO SALVO COM UTF-8`));
              this.addLog(createLog(node.id, label, 'INFO', `📄 CONTEÚDO:\n${contentToSave}\n`));
          }
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = false;
          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputCond = edgeIn ? this.context[edgeIn.source] : {};

          try {
              const checkCondition = new Function('input', `try { return ${conditionStr}; } catch(e) { return false; }`);
              result = checkCondition(inputCond);
          } catch (e) { result = false; }

          this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `Lógica (${conditionStr}) = ${result}`));
          this.context[node.id] = result;
          break;

        default:
          this.addLog(createLog(node.id, label, 'INFO', `OK.`));
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `ERRO FATAL: ${error.message}`));
      return false;
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO FLUXO (MODO REAL DATA) ---`));
    this.context = {}; 

    const queue: FlowNode[] = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);

        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⛔ Fim do ramo (Condição Falsa).`));
             continue; 
        }

        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
            queue.push(nextNode);
          }
        }
      } else {
        this.addLog(createLog(currentNode.id, currentNode.data.label, 'ERROR', `🛑 Parada por erro.`));
        break;
      }
    }
    this.addLog(createLog('system', 'System', 'INFO', `🏁 --- EXECUÇÃO CONCLUÍDA ---`));
  }
}

import React, { useCallback, useState, useEffect, useRef } from 'react';
