import React, { memo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
import { NodeStatus, NodeType } from '../types';

const CustomNode = ({ data, isConnectable, selected }: NodeProps) => {
  // Configuração visual baseada no status
  let statusStyles = 'border-gray-600 bg-gray-800';
  let statusLabel = null;
  let statusIcon = null;

  switch (data.status as NodeStatus) {
    case NodeStatus.RUNNING:
      statusStyles = 'border-yellow-400 bg-yellow-900/40 shadow-[0_0_15px_rgba(250,204,21,0.5)] ring-1 ring-yellow-400 animate-pulse';
      statusLabel = (
        <div className="absolute -top-6 left-0 right-0 flex justify-center">
             <span className="bg-yellow-500 text-black text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider animate-bounce">
                Processando...
             </span>
        </div>
      );
      statusIcon = <span className="animate-spin h-3 w-3 border-2 border-yellow-500 border-t-transparent rounded-full mr-2"></span>;
      break;

    case NodeStatus.SUCCESS:
      statusStyles = 'border-green-500 bg-green-900/30 shadow-[0_0_10px_rgba(34,197,94,0.3)]';
      statusIcon = <span className="text-green-400 mr-2">✔</span>;
      break;

    case NodeStatus.ERROR:
      statusStyles = 'border-red-500 bg-red-900/30 shadow-[0_0_10px_rgba(239,68,68,0.3)]';
      statusIcon = <span className="text-red-400 mr-2">✖</span>;
      break;

    case NodeStatus.IDLE:
    default:
      if (selected) statusStyles = 'border-blue-400 bg-gray-800 ring-1 ring-blue-400';
      statusIcon = <div className="rounded-full w-2 h-2 bg-gray-500 mr-2"></div>;
      break;
  }

  return (
    <div className={`px-4 py-3 rounded-lg border-2 min-w-[180px] transition-all duration-300 relative group ${statusStyles}`}>

      {/* Label Flutuante de Status (Só aparece executando) */}
      {statusLabel}

      <div className="flex items-center">
        {statusIcon}
        <div className="flex flex-col overflow-hidden">
          <div className="text-sm font-bold text-white truncate max-w-[150px]" title={data.label}>{data.label}</div>
          <div className="text-[9px] text-gray-400 uppercase tracking-widest font-mono">{data.type}</div>
        </div>
      </div>

      {/* Inputs (Top) */}
      <Handle
        type="target"
        position={Position.Top}
        isConnectable={isConnectable}
        className="w-3 h-3 bg-gray-400 border-2 border-gray-900 hover:bg-white transition-colors"
      />

      {/* Outputs (Bottom) */}
      <Handle
        type="source"
        position={Position.Bottom}
        isConnectable={isConnectable}
        className="w-3 h-3 bg-gray-400 border-2 border-gray-900 hover:bg-white transition-colors"
      />
    </div>
  );
};

export default memo(CustomNode);

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Aumentei o delay para permitir visualização clara da execução passo-a-passo
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  private parseConfigJSON(input: any): any {
      if (typeof input === 'object') return input;
      try { return JSON.parse(input); } catch (e) { return {}; }
  }

  // --- LÓGICA DE FETCH REPARADA E FORTALECIDA ---
  private async fetchRealData(url: string, options: any, nodeId: string, label: string): Promise<any> {
      let lastError: any;

      // 1. TENTATIVA DIRETA (Para APIs modernas com CORS habilitado)
      try {
          this.addLog(createLog(nodeId, label, 'INFO', `📡 Tentando conexão direta em: ${url}`));
          const response = await fetch(url, { ...options, mode: 'cors' }); // Tenta forçar CORS

          if (!response.ok) throw new Error(`Status ${response.status}`);

          const data = await response.json();
          this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Conexão Direta: OK`));
          return data;
      } catch (directError: any) {
          lastError = directError;
          // Não loga erro vermelho ainda, apenas aviso amarelo
          // this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Direto falhou (${directError.message}). Ativando Proxy...`));

          // 2. TENTATIVA PROXY (AllOrigins - Mais estável que corsproxy)
          // AllOrigins retorna o dado dentro de { contents: "string...", status: ... }
          try {
              const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 Roteando via Proxy Seguro...`));

              const response = await fetch(proxyUrl);
              if (!response.ok) throw new Error(`Proxy Status ${response.status}`);

              const wrapperData = await response.json();

              if (!wrapperData.contents) throw new Error("Proxy não retornou conteúdo.");

              // O PULO DO GATO: AllOrigins retorna 'contents' como string. TEM QUE PARSEAR NOVAMENTE.
              try {
                  const finalData = JSON.parse(wrapperData.contents);
                  this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Dados recebidos e decodificados via Proxy.`));
                  return finalData;
              } catch (parseError) {
                  // Se não for JSON (ex: HTML), retorna o texto puro
                  return { raw_content: wrapperData.contents };
              }

          } catch (proxyError: any) {
               throw new Error(`Falha em todas as rotas. Verifique a URL. (${proxyError.message})`);
          }
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    let { type, config, label } = node.data;
    if (!type && node.type) { type = node.type as NodeType; node.data.type = type; }
    if (!label) label = type || 'Node';

    // 1. VISUALIZAÇÃO: Marca como rodando
    this.updateNodeStatus(node.id, NodeStatus.RUNNING);

    // Pequeno delay inicial para o usuário ver o "Running" acender
    await wait(500);

    try {
      // Delay de simulação para dar "peso" à execução
      await wait(1500); 

      switch (type) {
        case NodeType.START:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🟢 Gatilho Inicial Disparado.`));
            break;

        case NodeType.HTTP_REQUEST:
          const method = (config?.method || 'GET').toUpperCase();
          const url = config?.url;

          if (!url) throw new Error("URL não configurada neste nó.");

          const customHeaders = this.parseConfigJSON(config?.headers) || {};
          const isBodyMethod = ['POST', 'PUT', 'PATCH'].includes(method);
          const headers: Record<string, string> = { ...customHeaders };
          if (isBodyMethod && !headers['Content-Type']) headers['Content-Type'] = 'application/json';
          const body = isBodyMethod ? JSON.stringify(this.parseConfigJSON(config?.body)) : undefined;

          const responseData = await this.fetchRealData(url, { method, headers, body }, node.id, label);

          // Armazena no contexto GLOBAL para os próximos nós
          this.context[node.id] = responseData;

          // Atalho "input" para facilitar a vida nos Ifs
          this.context['last_run'] = responseData; 
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = false;

          // Pega dados do nó conectado anteriormente
          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputData = edgeIn ? this.context[edgeIn.source] : {};

          if (!edgeIn) {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Este IF não está conectado a nada. Assumindo Falso.`));
          }

          try {
              // Contexto de avaliação seguro
              const checkCondition = new Function('input', 'data', `
                  try { 
                      // Compatibilidade: permite usar 'input' ou 'data'
                      return ${conditionStr}; 
                  } catch(e) { 
                      return false; 
                  }
              `);
              result = checkCondition(inputData, inputData);
          } catch (e) { 
              result = false; 
          }

          this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `⚖️ Avaliação: (${conditionStr}) => ${result ? 'VERDADEIRO' : 'FALSO'}`));
          this.context[node.id] = result;
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          const fileName = config?.fileName || `resultado-${Date.now()}.txt`;

          if (incomingEdge && this.context[incomingEdge.source]) {
            const dataToSave = this.context[incomingEdge.source];
            let contentStr = "";

            if (typeof dataToSave === 'object') {
                contentStr = JSON.stringify(dataToSave, null, 2);
            } else {
                contentStr = String(dataToSave);
            }

            if (this.onFileGenerated) {
                this.onFileGenerated({
                    id: crypto.randomUUID(),
                    name: fileName,
                    content: contentStr,
                    extension: config?.fileFormat || 'txt',
                    timestamp: Date.now(),
                    nodeId: node.id
                });
                this.addLog(createLog(node.id, label, 'SUCCESS', `💾 Arquivo "${fileName}" gerado na aba Arquivos.`));
            }
          } else {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Nada para salvar. O nó anterior não enviou dados.`));
          }
          break;

        case NodeType.DELAY:
           this.addLog(createLog(node.id, label, 'INFO', `⏳ Esperando ${config?.ms || 1000}ms...`));
           await wait(config?.ms || 1000);
           break;

        case NodeType.LOGGER:
            // Loga o contexto inteiro para debug
            this.addLog(createLog(node.id, label, 'INFO', JSON.stringify(this.context, null, 2)));
            break;

        default:
          break;
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `❌ ERRO: ${error.message}`));
      return false; // Interrompe o fluxo em caso de erro fatal
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO FLUXO ---`));
    this.context = {}; 

    // Identifica nós iniciais
    const startNodes = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const queue: FlowNode[] = startNodes.length > 0 ? startNodes : [this.nodes[0]];
    const visited = new Set<string>();

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode || visited.has(currentNode.id)) continue;

      // --- SCROLL AUTOMÁTICO PARA O NÓ ATUAL (Opcional, mas legal) ---
      // (Não implementado aqui para não quebrar o React Flow, mas a visualização do NodeStatus resolve)

      const success = await this.executeNode(currentNode);
      visited.add(currentNode.id);

      if (success) {
        // Lógica de IF: Se for IF e deu false, não continua
        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⛔ Fluxo interrompido (Condição Falsa).`));
             continue; 
        }

        // Encontra próximos nós
        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode && !visited.has(nextNode.id)) {
            queue.push(nextNode);
          }
        }
      } else {
        this.addLog(createLog('system', 'System', 'ERROR', `🛑 Fluxo parado devido a erro no nó "${currentNode.data.label}".`));
        break;
      }
    }

    // Limpa status visuais após um tempo
    setTimeout(() => {
        this.setNodes((nds: FlowNode[]) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));
    }, 3000);

    this.addLog(createLog('system', 'System', 'INFO', `🏁 --- FIM DA EXECUÇÃO ---`));
  }
}

