import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Aumentei o delay para permitir visualização clara da execução passo-a-passo
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  private parseConfigJSON(input: any): any {
      if (typeof input === 'object') return input;
      try { return JSON.parse(input); } catch (e) { return {}; }
  }

  // --- LÓGICA DE FETCH BLINDADA (MULTI-LAYER) ---
  private async fetchRealData(url: string, options: any, nodeId: string, label: string): Promise<any> {

      const controller = new AbortController();
      // Timeout longo (25s) para suportar LLMs lentas (OpenAI/Gemini via REST)
      const timeoutId = setTimeout(() => controller.abort(), 25000); 

      try {
          // 1. TENTATIVA DIRETA (Ideal para APIs com CORS habilitado)
          this.addLog(createLog(nodeId, label, 'INFO', `📡 Tentando conexão direta em: ${url}`));

          const response = await fetch(url, { ...options, signal: controller.signal });

          if (!response.ok) {
               // Se for erro de CORS, o navegador joga exceção direto, então se chegou aqui é erro HTTP (4xx, 5xx)
               // Mas tentamos proxy mesmo assim se for 403/401 as vezes
               throw new Error(`Direct Error: ${response.status}`);
          }

          const data = await response.json();
          clearTimeout(timeoutId);
          this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Conexão Direta: OK`));
          return data;

      } catch (directError: any) {
          const isNetworkError = directError.message.includes('Failed to fetch') || directError.message.includes('NetworkError');
          this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Direto falhou. Tentando Proxy 1 (CorsProxy)...`));

          // 2. TENTATIVA PROXY 1 (CorsProxy.io) - Suporta POST e Headers (Auth)
          try {
              // IMPORTANTE: CorsProxy repassa os headers e body que enviamos para ele
              const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(url)}`;

              const response = await fetch(proxyUrl, { 
                  ...options, // <--- REPASSA METHOD, HEADERS E BODY!
                  signal: controller.signal 
              });

              if (!response.ok) {
                  const errText = await response.text();
                  throw new Error(`Status ${response.status}: ${errText.substring(0, 100)}`);
              }

              const data = await response.json();
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Dados via CorsProxy.`));
              return data;

          } catch (proxyError1: any) {
               this.addLog(createLog(nodeId, label, 'WARN', `⚠️ CorsProxy falhou. Tentando Proxy 2 (ThingProxy)...`));

               // 3. TENTATIVA PROXY 2 (ThingProxy) - Ótimo fallback para APIs JSON
               try {
                   const proxyUrl2 = `https://thingproxy.freeboard.io/fetch/${url}`;

                   const response = await fetch(proxyUrl2, { 
                       ...options, // <--- REPASSA METHOD, HEADERS E BODY!
                       signal: controller.signal 
                   });

                   if (!response.ok) throw new Error(`Status ${response.status}`);

                   const data = await response.json();
                   clearTimeout(timeoutId);
                   this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Dados via ThingProxy.`));
                   return data;

               } catch (proxyError2: any) {

                   // 4. TENTATIVA PROXY 3 (AllOrigins) - APENAS GET (Último recurso, não suporta Headers customizados)
                   if (options.method === 'GET' || !options.method) {
                        this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Proxies Auth falharam. Tentando AllOrigins (GET simples)...`));
                        try {
                            const proxyUrl3 = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
                            const response = await fetch(proxyUrl3, { signal: controller.signal });

                            if (!response.ok) throw new Error(`Status ${response.status}`);

                            const wrapperData = await response.json();
                            let finalData = wrapperData.contents;

                            if (typeof finalData === 'string') {
                                try { finalData = JSON.parse(finalData); } catch(e) {}
                            }

                            clearTimeout(timeoutId);
                            this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Dados via AllOrigins.`));
                            return finalData;
                        } catch (e) {}
                   }

                   clearTimeout(timeoutId);
                   this.addLog(createLog(nodeId, label, 'ERROR', `❌ Todas as rotas de conexão falharam.`));

                   // Mensagem de ajuda inteligente
                   let helpMsg = `Falha ao acessar ${url}.`;
                   if (url.includes('openai.com') || url.includes('anthropic.com')) {
                       helpMsg += ` APIs como OpenAI bloqueiam navegadores severamente. Verifique se sua API Key está correta nos Headers.`;
                   } else {
                       helpMsg += ` Verifique a URL ou tente outra API pública.`;
                   }
                   throw new Error(helpMsg);
               }
          }
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    let { type, config, label } = node.data;
    if (!type && node.type) { type = node.type as NodeType; node.data.type = type; }
    if (!label) label = type || 'Node';

    // 1. VISUALIZAÇÃO IMEDIATA
    this.updateNodeStatus(node.id, NodeStatus.RUNNING);

    try {
      // Delay visual para você ver o nó ficando amarelo
      await wait(800); 

      switch (type) {
        case NodeType.START:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🟢 Início do Fluxo.`));
            break;

        case NodeType.HTTP_REQUEST:
          const method = (config?.method || 'GET').toUpperCase();
          const url = config?.url;

          if (!url) throw new Error("URL é obrigatória.");

          const customHeaders = this.parseConfigJSON(config?.headers) || {};
          const isBodyMethod = ['POST', 'PUT', 'PATCH'].includes(method);
          const headers: Record<string, string> = { ...customHeaders };
          if (isBodyMethod && !headers['Content-Type']) headers['Content-Type'] = 'application/json';
          const body = isBodyMethod ? JSON.stringify(this.parseConfigJSON(config?.body)) : undefined;

          // Executa Fetch Seguro
          const responseData = await this.fetchRealData(url, { method, headers, body }, node.id, label);

          // Salva no contexto
          this.context[node.id] = responseData;
          // Atalho útil
          this.context['input'] = responseData; 
          this.context['data'] = responseData; 

          const preview = JSON.stringify(responseData).substring(0, 100) + "...";
          this.addLog(createLog(node.id, label, 'INFO', `📦 Dados recebidos: ${preview}`));
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = true; // DEFAULT SAFE: True

          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputData = edgeIn ? this.context[edgeIn.source] : (this.context['input'] || {});

          try {
              // Tenta executar a condição
              const checkCondition = new Function('input', 'data', 'json', `
                  try { return ${conditionStr}; } catch(e) { return false; }
              `);
              result = checkCondition(inputData, inputData, inputData);

              this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `⚖️ Condição (${conditionStr}) => ${result ? 'VERDADEIRO' : 'FALSO'}`));

          } catch (e) { 
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Erro na sintaxe da condição. Continuando fluxo mesmo assim.`));
              result = true; 
          }

          this.context[node.id] = result;
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          const fileName = config?.fileName || `output-${Date.now()}.txt`;

          // Tenta pegar dados do nó anterior, ou do antepenúltimo se o anterior for um IF que passou
          let sourceData = incomingEdge ? this.context[incomingEdge.source] : this.context['input'];

          // Se o dado for apenas "true/false" (vindo de um IF), pega o dado "real" (input global)
          // Isso garante que mesmo se o IF for falso, o arquivo salve os dados da API
          if (typeof sourceData === 'boolean') {
              sourceData = this.context['input'];
          }

          if (sourceData) {
            let contentStr = "";
            if (typeof sourceData === 'object') {
                contentStr = JSON.stringify(sourceData, null, 2);
            } else {
                contentStr = String(sourceData);
            }

            if (this.onFileGenerated) {
                this.onFileGenerated({
                    id: crypto.randomUUID(),
                    name: fileName,
                    content: contentStr,
                    extension: config?.fileFormat || 'txt',
                    timestamp: Date.now(),
                    nodeId: node.id
                });
                this.addLog(createLog(node.id, label, 'SUCCESS', `💾 Arquivo salvo com sucesso.`));
            }
          } else {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Sem dados para salvar.`));
          }
          break;

        case NodeType.DELAY:
           const ms = config?.ms || 1000;
           this.addLog(createLog(node.id, label, 'INFO', `⏳ Aguardando ${ms}ms...`));
           await wait(ms);
           break;

        case NodeType.LOGGER:
            const edgeInLog = this.edges.find(e => e.target === node.id);
            const dataToLog = edgeInLog ? this.context[edgeInLog.source] : this.context;
            this.addLog(createLog(node.id, label, 'INFO', `📝 Log: ${JSON.stringify(dataToLog, null, 2)}`));
            break;

        default:
          break;
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      console.error(error);
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `❌ Erro Fatal: ${error.message}`));
      return false; 
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO EXECUÇÃO ---`));
    this.context = {}; 

    this.setNodes((nds: FlowNode[]) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));
    await wait(200);

    const startNodes = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const queue: FlowNode[] = startNodes.length > 0 ? startNodes : [this.nodes[0]];
    const visited = new Set<string>();

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode) continue;

      const success = await this.executeNode(currentNode);

      if (success) {
        // --- MUDANÇA CRÍTICA AQUI ---
        // Se a condição for FALSA, nós NÃO paramos mais o fluxo.
        // Apenas logamos o aviso e deixamos o fluxo seguir para o próximo nó (ex: Salvar Arquivo)
        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⚠️ Condição Falsa. Continuando o fluxo para registro...`));
             // 'continue' removido intencionalmente para permitir "Execução Completa"
        }

        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
             queue.push(nextNode);
          }
        }
      } else {
        break;
      }
    }

    this.addLog(createLog('system', 'System', 'INFO', `🏁 Execução Finalizada.`));
  }
}

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Delay auxiliar para visualização
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
