              }
          }

          // 6. ALL ORIGINS (GET ONLY)
          if (!options.method || options.method === 'GET') {
               try {
                   this.addLog(createLog(nodeId, label, 'INFO', `🔄 [6/6] Tentando AllOrigins (GET)...`));
                   const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
                   const response = await fetch(proxyUrl, { signal: controller.signal });
                   const wrapper = await response.json();
                   if (wrapper.contents) {
                       clearTimeout(timeoutId);
                       try { return JSON.parse(wrapper.contents); } catch { return wrapper.contents; }
                   }
               } catch (e) {}
          }

          clearTimeout(timeoutId);
          this.addLog(createLog(nodeId, label, 'ERROR', `❌ Todas as rotas falharam.`));
          throw new Error(`Não foi possível conectar a ${url} através de nenhum proxy.`);

      } catch (finalError: any) {
          clearTimeout(timeoutId);
          throw finalError;
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    let { type, config, label } = node.data;
    if (!type && node.type) { type = node.type as NodeType; node.data.type = type; }
    if (!label) label = type || 'Node';

    this.updateNodeStatus(node.id, NodeStatus.RUNNING);

    try {
      await wait(800); 

      switch (type) {
        case NodeType.START:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🟢 Início do Fluxo.`));
            break;

        case NodeType.HTTP_REQUEST:
          const method = (config?.method || 'GET').toUpperCase();
          const url = config?.url;

          if (!url) throw new Error("URL é obrigatória.");

          const customHeaders = this.parseHeaders(config?.headers);

          // --- VALIDAÇÃO PRÉ-REQ: Detecta chaves placeholder ---
          if (JSON.stringify(customHeaders).includes('YOUR_API_KEY') || url.includes('YOUR_API_KEY')) {
              throw new Error("CONFIGURAÇÃO NECESSÁRIA: Você está usando uma chave de exemplo ('YOUR_API_KEY'). Edite o Node e insira sua credencial real.");
          }

          // --- VALIDAÇÃO PRÉ-REQ: Detecta falta de Auth para OpenAI ---
          if (url.includes('api.openai.com') && !customHeaders['Authorization'] && !customHeaders['authorization']) {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Detectada URL da OpenAI sem header 'Authorization'. A requisição provavelmente falhará.`));
          }

          const isBodyMethod = ['POST', 'PUT', 'PATCH'].includes(method);
          const headers: Record<string, string> = { ...customHeaders };
          if (isBodyMethod && !headers['Content-Type']) headers['Content-Type'] = 'application/json';
          const body = isBodyMethod ? JSON.stringify(this.parseConfigJSON(config?.body)) : undefined;

          // Executa Fetch Seguro
          const responseData = await this.fetchRealData(url, { method, headers, body }, node.id, label);

          // Salva no contexto
          this.context[node.id] = responseData;
          this.context['input'] = responseData; 
          this.context['data'] = responseData; 

          const preview = JSON.stringify(responseData).substring(0, 100) + "...";
          this.addLog(createLog(node.id, label, 'INFO', `📦 Dados recebidos: ${preview}`));
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = true;

          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputData = edgeIn ? this.context[edgeIn.source] : (this.context['input'] || {});

          try {
              const checkCondition = new Function('input', 'data', 'json', `
                  try { return ${conditionStr}; } catch(e) { return false; }
              `);
              result = checkCondition(inputData, inputData, inputData);
              this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `⚖️ Condição (${conditionStr}) => ${result ? 'VERDADEIRO' : 'FALSO'}`));
          } catch (e) { 
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Erro na sintaxe da condição. Continuando fluxo (TRUE).`));
              result = true; 
          }
          this.context[node.id] = result;
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          const fileName = config?.fileName || `output-${Date.now()}.txt`;

          let sourceData = incomingEdge ? this.context[incomingEdge.source] : this.context['input'];
          if (typeof sourceData === 'boolean') sourceData = this.context['input'];

          if (sourceData) {
            let contentStr = typeof sourceData === 'object' ? JSON.stringify(sourceData, null, 2) : String(sourceData);
            if (this.onFileGenerated) {
                this.onFileGenerated({
                    id: crypto.randomUUID(),
                    name: fileName,
                    content: contentStr,
                    extension: config?.fileFormat || 'txt',
                    timestamp: Date.now(),
                    nodeId: node.id
                });
                this.addLog(createLog(node.id, label, 'SUCCESS', `💾 Arquivo salvo.`));
            }
          } else {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Sem dados para salvar.`));
          }
          break;

        case NodeType.DELAY:
           const ms = config?.ms || 1000;
           this.addLog(createLog(node.id, label, 'INFO', `⏳ Aguardando ${ms}ms...`));
           await wait(ms);
           break;

        case NodeType.LOGGER:
            const edgeInLog = this.edges.find(e => e.target === node.id);
            const dataToLog = edgeInLog ? this.context[edgeInLog.source] : this.context;
            this.addLog(createLog(node.id, label, 'INFO', `📝 Log: ${JSON.stringify(dataToLog, null, 2)}`));
            break;

        case NodeType.WEBHOOK:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🔔 Webhook acionado.`));
            break;

        default:
          break;
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      console.error(error);
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `❌ ${error.message}`));
      return false; 
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO EXECUÇÃO ---`));
    this.context = {}; 

    this.setNodes((nds: FlowNode[]) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));
    await wait(200);

    const startNodes = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const queue: FlowNode[] = startNodes.length > 0 ? startNodes : [this.nodes[0]];

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode) continue;

      const success = await this.executeNode(currentNode);

      if (success) {
        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⚠️ Condição Falsa. Fluxo segue, mas verifique a lógica.`));
        }

        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
             queue.push(nextNode);
          }
        }
      } else {
        break;
      }
    }

    this.addLog(createLog('system', 'System', 'INFO', `🏁 Execução Finalizada.`));
  }
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { FlowSchema } from '../types';

// Initialize Gemini Client
// A API Key deve vir exclusivamente do ambiente. Chaves hardcoded de exemplo causam erro 403.
const API_KEY = process.env.API_KEY;
const ai = API_KEY ? new GoogleGenAI({ apiKey: API_KEY }) : null;

export const generateFlowFromPrompt = async (userPrompt: string): Promise<{ text: string, flowData?: FlowSchema }> => {
  if (!ai) {
    return { 
      text: "⚠️ **Configuração Necessária**: Nenhuma API Key detectada. \n\nPara usar o Chat IA, você precisa configurar a variável de ambiente `API_KEY` com uma chave válida do Google Gemini (obtenha em aistudio.google.com).", 
      flowData: undefined 
    };
  }

  try {
    const model = 'gemini-3-flash-preview'; 

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        { role: 'user', parts: [{ text: SYSTEM_PROMPT }] },
        { role: 'user', parts: [{ text: `Solicitação do usuário: ${userPrompt}` }] }
      ],
      config: {
        temperature: 0.2, 
      }
    });

    const text = response.text || "Erro ao gerar resposta.";
    let flowData: FlowSchema | undefined;

    // --- ESTRATÉGIA DE PARSING ROBUSTA ---
    let jsonString = '';

    // 1. Tenta extrair de bloco markdown específico ```json ... ```
    const jsonBlockMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonBlockMatch && jsonBlockMatch[1]) {
        jsonString = jsonBlockMatch[1];
    } 
    // 2. Tenta extrair de bloco de código genérico ``` ... ```
    else {
        const genericBlockMatch = text.match(/```\s*([\s\S]*?)\s*```/);
        if (genericBlockMatch && genericBlockMatch[1]) {
            jsonString = genericBlockMatch[1];
        } 
        // 3. Fallback: Tenta parsear o texto inteiro se parecer um JSON (começa com { e termina com })
        else if (text.trim().startsWith('{') && text.trim().endsWith('}')) {
            jsonString = text;
        }
    }

    if (jsonString) {
      try {
        const parsed = JSON.parse(jsonString);
        // Validação mínima do schema
        if (parsed.nodes && Array.isArray(parsed.nodes) && parsed.edges && Array.isArray(parsed.edges)) {
          flowData = parsed as FlowSchema;
        }
      } catch (e) {
        console.error("Falha ao parsear JSON do fluxo gerado", e);
      }
    }

    return { text, flowData };

  } catch (error: any) {
    console.error("Gemini API Error:", error);

    let friendlyError = "Erro desconhecido ao conectar com a IA.";

    // Tratamento específico de erros comuns
    const errorMsg = error.message || JSON.stringify(error);

    if (errorMsg.includes('403') || errorMsg.includes('PERMISSION_DENIED')) {
        friendlyError = "⛔ **Acesso Negado (403)**: A API Key fornecida não é válida ou não tem permissão para acessar o modelo `gemini-3-flash-preview`. \n\nVerifique se a 'Generative Language API' está habilitada no Google Cloud Console.";
    } else if (errorMsg.includes('404') || errorMsg.includes('NOT_FOUND')) {
        friendlyError = "⛔ **Modelo Não Encontrado (404)**: O modelo `gemini-3-flash-preview` não está acessível. A chave pode estar incorreta ou o modelo indisponível na sua região.";
    } else if (errorMsg.includes('429')) {
        friendlyError = "⏳ **Limite de Taxa Excedido (429)**: Você fez muitas requisições em pouco tempo. Tente novamente em alguns instantes.";
    }

    return { text: friendlyError, flowData: undefined };
  }
};

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Delay auxiliar para visualização
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  private parseConfigJSON(input: any): any {
      if (typeof input === 'object') return input;
      try { return JSON.parse(input); } catch (e) { return {}; }
  }

  // Novo parser robusto de Headers: Aceita JSON ou formato "Key: Value" e faz trim
  private parseHeaders(input: any): Record<string, string> {
      if (!input) return {};
      if (typeof input === 'object') return input;

      try {
          return JSON.parse(input);
      } catch (e) {
          // Fallback: Tenta parsear formato texto (ex: Postman raw headers)
          const headers: Record<string, string> = {};
          const lines = input.toString().split('\n');

          for (const line of lines) {
              const separatorIndex = line.indexOf(':');
              if (separatorIndex > -1) {
                  // Remove quotes extras que o usuário possa ter colado no início/fim da chave ou valor
                  let key = line.substring(0, separatorIndex).trim().replace(/^['"]|['"]$/g, '');
                  let value = line.substring(separatorIndex + 1).trim().replace(/^['"]|['"]$/g, '');

                  if (key) {
                      headers[key] = value;
                  }
              }
          }
          return headers;
      }
  }

  // --- LÓGICA DE FETCH REFORÇADA (5 LAYERS) ---
  private async fetchRealData(url: string, options: any, nodeId: string, label: string): Promise<any> {

      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 45000); 

      // Verifica se nós enviamos autenticação (para saber se o erro é nosso ou do proxy)
      const hasAuth = options.headers && Object.keys(options.headers).some(k => k.toLowerCase() === 'authorization');

      // Helper para processar resposta e EXTRAIR DETALHES DO ERRO
      const processResponse = async (response: Response, sourceName: string) => {
          if (!response.ok) {
              let errorDetails = "";
              try {
                  const text = await response.text();
                  try {
                      const json = JSON.parse(text);
                      errorDetails = json.error?.message || json.message || json.error || text;
                  } catch {
                      errorDetails = text.substring(0, 300);
                  }
              } catch {
                  errorDetails = "Sem detalhes do servidor.";
              }

              if (response.status === 401 || (response.status === 403 && !errorDetails.includes('cors-anywhere'))) {
                  let hint = "";
                  // Detecta se o usuário esqueceu de substituir a chave de exemplo
                  if (errorDetails.includes("YOUR_API_KEY") || errorDetails.includes("Incorrect API key")) {
                       hint = " 💡 DICA: Você está usando uma chave de exemplo ('YOUR_API_KEY'). Edite as configurações deste Node e insira sua chave real.";
                  } else if (errorDetails.toLowerCase().includes("provide an api key")) {
                       hint = " 💡 DICA: O header 'Authorization' parece estar ausente ou incorreto. Verifique se o formato é 'Authorization: Bearer SK-...'";
                  }
                  throw new Error(`AUTH_ERROR: O servidor recusou a conexão (${response.status}) via ${sourceName}. Mensagem da API: "${errorDetails}".${hint}`);
              }
              throw new Error(`${sourceName} Error ${response.status}: ${errorDetails}`);
          }
          return response.json();
      };

      // Helper para tratar erro de proxy: Se o erro for "Chave Ausente" mas nós enviamos a chave,
      // significa que o proxy comeu o header. Então não devemos lançar erro, e sim continuar tentando o próximo proxy.
      const handleProxyError = (e: any, sourceName: string) => {
          if (e.message.includes('AUTH_ERROR')) {
              const msg = e.message.toLowerCase();
              // Se o erro diz que não fornecemos chave, mas hasAuth é true, é culpa do proxy.
              const isMissingKeyError = msg.includes("didn't provide an api key") || msg.includes("provide your api key");

              if (hasAuth && isMissingKeyError) {
                  this.addLog(createLog(nodeId, label, 'WARN', `⚠️ ${sourceName} falhou em repassar a autenticação (Header Stripped). Tentando próxima rota...`));
                  return; // Retorna sem lançar erro, permitindo o código seguir para o próximo try/catch
              }
              throw e; // Se a chave estava errada (Incorrect API Key), lança o erro para parar tudo.
          }
          // Se for outro erro (timeout, network), apenas loga e deixa tentar o próximo
      };

      try {
          // 1. TENTATIVA DIRETA
          this.addLog(createLog(nodeId, label, 'INFO', `📡 [1/5] Tentando conexão direta...`));
          try {
              const response = await fetch(url, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'Direct');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Conexão Direta: OK`));
              return data;
          } catch (e: any) {
              // Direct falhando com auth pode ser CORS do browser bloqueando header. Segue o jogo.
              if (e.message.includes('AUTH_ERROR')) {
                   this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Direct retornou 401. O navegador pode ter bloqueado o Header. Tentando proxies...`));
              } else {
                   this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Direto falhou. Iniciando rota de proxies...`));
              }
          }

          // 2. CORS PROXY IO
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 [2/5] Tentando CorsProxy.io...`));
              const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(url)}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'CorsProxy');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via CorsProxy`));
              return data;
          } catch (e: any) {
              handleProxyError(e, 'CorsProxy');
          }

          // 3. CODE TABS
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 [3/5] Tentando CodeTabs...`));
              const proxyUrl = `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(url)}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'CodeTabs');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via CodeTabs`));
              return data;
          } catch (e: any) {
              handleProxyError(e, 'CodeTabs');
          }

          // 4. THING PROXY
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 [4/5] Tentando ThingProxy...`));
              const proxyUrl = `https://thingproxy.freeboard.io/fetch/${url}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'ThingProxy');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via ThingProxy`));
              return data;
          } catch (e: any) {
              handleProxyError(e, 'ThingProxy');
          }

          // 5. CORS ANYWHERE (ULTIMATE FALLBACK)
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🛡️ [5/5] Tentando CorsAnywhere (Backup)...`));
              const proxyUrl = `https://cors-anywhere.herokuapp.com/${url}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });

              if (response.status === 403) {
                   throw new Error("REQUIRES_ACTIVATION");
              }

              const data = await processResponse(response, 'CorsAnywhere');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via CorsAnywhere`));
              return data;

          } catch (e: any) {
              if (e.message.includes('AUTH_ERROR')) throw e; // Se CorsAnywhere falhar com Auth, é erro real do usuário
              if (e.message === 'REQUIRES_ACTIVATION' || e.message.includes('See /corsdemo')) {
                  throw new Error(`
                      🔒 BLOQUEIO DE SEGURANÇA DETECTADO.
                      Para usar APIs privadas no navegador:
                      1. Abra uma nova aba: https://cors-anywhere.herokuapp.com/corsdemo
                      2. Clique em "Request temporary access"
                      3. Volte aqui e tente novamente.
                  `);
              }
          }

          // 6. ALL ORIGINS (GET ONLY)
          if (!options.method || options.method === 'GET') {
               try {
                   this.addLog(createLog(nodeId, label, 'INFO', `🔄 [6/6] Tentando AllOrigins (GET)...`));
                   const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
                   const response = await fetch(proxyUrl, { signal: controller.signal });
                   const wrapper = await response.json();
                   if (wrapper.contents) {
                       clearTimeout(timeoutId);
                       try { return JSON.parse(wrapper.contents); } catch { return wrapper.contents; }
                   }
               } catch (e) {}
          }

          clearTimeout(timeoutId);
          this.addLog(createLog(nodeId, label, 'ERROR', `❌ Todas as rotas falharam.`));
          throw new Error(`Não foi possível conectar a ${url} através de nenhum proxy.`);

      } catch (finalError: any) {
          clearTimeout(timeoutId);
          throw finalError;
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    let { type, config, label } = node.data;
    if (!type && node.type) { type = node.type as NodeType; node.data.type = type; }
    if (!label) label = type || 'Node';

    this.updateNodeStatus(node.id, NodeStatus.RUNNING);

    try {
      await wait(800); 

      switch (type) {
        case NodeType.START:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🟢 Início do Fluxo.`));
            break;

        case NodeType.HTTP_REQUEST:
          const method = (config?.method || 'GET').toUpperCase();
          const url = config?.url;

          if (!url) throw new Error("URL é obrigatória.");

          const customHeaders = this.parseHeaders(config?.headers);

          // --- VALIDAÇÃO PRÉ-REQ: Detecta chaves placeholder ---
          if (JSON.stringify(customHeaders).includes('YOUR_API_KEY') || url.includes('YOUR_API_KEY')) {
              throw new Error("CONFIGURAÇÃO NECESSÁRIA: Você está usando uma chave de exemplo ('YOUR_API_KEY'). Edite o Node e insira sua credencial real.");
          }

          // --- VALIDAÇÃO PRÉ-REQ: Detecta falta de Auth para OpenAI ---
          if (url.includes('api.openai.com') && !customHeaders['Authorization'] && !customHeaders['authorization']) {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Detectada URL da OpenAI sem header 'Authorization'. A requisição provavelmente falhará.`));
          }

          const isBodyMethod = ['POST', 'PUT', 'PATCH'].includes(method);
          const headers: Record<string, string> = { ...customHeaders };
          if (isBodyMethod && !headers['Content-Type']) headers['Content-Type'] = 'application/json';
          const body = isBodyMethod ? JSON.stringify(this.parseConfigJSON(config?.body)) : undefined;

          // Executa Fetch Seguro
          const responseData = await this.fetchRealData(url, { method, headers, body }, node.id, label);

          // Salva no contexto
          this.context[node.id] = responseData;
          this.context['input'] = responseData; 
          this.context['data'] = responseData; 

          const preview = JSON.stringify(responseData).substring(0, 100) + "...";
          this.addLog(createLog(node.id, label, 'INFO', `📦 Dados recebidos: ${preview}`));
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = true;

          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputData = edgeIn ? this.context[edgeIn.source] : (this.context['input'] || {});

          try {
              const checkCondition = new Function('input', 'data', 'json', `
                  try { return ${conditionStr}; } catch(e) { return false; }
              `);
              result = checkCondition(inputData, inputData, inputData);
              this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `⚖️ Condição (${conditionStr}) => ${result ? 'VERDADEIRO' : 'FALSO'}`));
          } catch (e) { 
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Erro na sintaxe da condição. Continuando fluxo (TRUE).`));
              result = true; 
          }
          this.context[node.id] = result;
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          const fileName = config?.fileName || `output-${Date.now()}.txt`;

          let sourceData = incomingEdge ? this.context[incomingEdge.source] : this.context['input'];
          if (typeof sourceData === 'boolean') sourceData = this.context['input'];

          if (sourceData) {
            let contentStr = typeof sourceData === 'object' ? JSON.stringify(sourceData, null, 2) : String(sourceData);
            if (this.onFileGenerated) {
                this.onFileGenerated({
                    id: crypto.randomUUID(),
                    name: fileName,
                    content: contentStr,
                    extension: config?.fileFormat || 'txt',
                    timestamp: Date.now(),
                    nodeId: node.id
                });
                this.addLog(createLog(node.id, label, 'SUCCESS', `💾 Arquivo salvo.`));
            }
          } else {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Sem dados para salvar.`));
          }
          break;

        case NodeType.DELAY:
           const ms = config?.ms || 1000;
           this.addLog(createLog(node.id, label, 'INFO', `⏳ Aguardando ${ms}ms...`));
           await wait(ms);
           break;

        case NodeType.LOGGER:
            const edgeInLog = this.edges.find(e => e.target === node.id);
            const dataToLog = edgeInLog ? this.context[edgeInLog.source] : this.context;
            this.addLog(createLog(node.id, label, 'INFO', `📝 Log: ${JSON.stringify(dataToLog, null, 2)}`));
            break;

        case NodeType.WEBHOOK:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🔔 Webhook acionado.`));
            break;

        default:
          break;
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      console.error(error);
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `❌ ${error.message}`));
      return false; 
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO EXECUÇÃO ---`));
    this.context = {}; 

    this.setNodes((nds: FlowNode[]) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));
    await wait(200);

    const startNodes = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const queue: FlowNode[] = startNodes.length > 0 ? startNodes : [this.nodes[0]];

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode) continue;

      const success = await this.executeNode(currentNode);

      if (success) {
        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⚠️ Condição Falsa. Fluxo segue, mas verifique a lógica.`));
        }

        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
             queue.push(nextNode);
          }
        }
      } else {
        break;
      }
    }

    this.addLog(createLog('system', 'System', 'INFO', `🏁 Execução Finalizada.`));
  }
}

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { FlowSchema } from '../types';

// Initialize Gemini Client
// A API Key deve vir exclusivamente do ambiente.
const API_KEY = process.env.API_KEY;

// Chave de exemplo pública que causa erro 403 frequente em tutoriais
const INVALID_EXAMPLE_KEY = 'AIzaSyDmUgmObZ_HsSe9BHdJaUbqgdSud4Qrl6Y';

const ai = (API_KEY && API_KEY !== INVALID_EXAMPLE_KEY) ? new GoogleGenAI({ apiKey: API_KEY }) : null;

export const generateFlowFromPrompt = async (userPrompt: string): Promise<{ text: string, flowData?: FlowSchema }> => {
  // 1. Verificação de Chave Inválida Conhecida
  if (API_KEY === INVALID_EXAMPLE_KEY) {
    return {
      text: "⛔ **Chave de Exemplo Detectada**\n\nA chave que você está usando (`AIzaSyDm...`) é uma chave de demonstração pública e **não funciona** para gerar fluxos.\n\nPor favor, gere uma chave válida gratuitamente em [Google AI Studio](https://aistudio.google.com/app/apikey) e atualize a variável de ambiente `API_KEY`.",
      flowData: undefined
    };
  }

  // 2. Verificação de Ausência de Chave
  if (!ai) {
    return { 
      text: "⚠️ **Configuração Necessária**: Nenhuma API Key válida detectada. \n\nPara usar o Chat IA, você precisa configurar a variável de ambiente `API_KEY` com uma chave do Google Gemini.", 
      flowData: undefined 
    };
  }

  try {
    const model = 'gemini-3-flash-preview'; 

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        { role: 'user', parts: [{ text: SYSTEM_PROMPT }] },
        { role: 'user', parts: [{ text: `Solicitação do usuário: ${userPrompt}` }] }
      ],
      config: {
        temperature: 0.2, 
      }
    });

    const text = response.text || "Erro ao gerar resposta.";
    let flowData: FlowSchema | undefined;

    // --- ESTRATÉGIA DE PARSING ROBUSTA ---
    let jsonString = '';

    // 1. Tenta extrair de bloco markdown específico ```json ... ```
    const jsonBlockMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonBlockMatch && jsonBlockMatch[1]) {
        jsonString = jsonBlockMatch[1];
    } 
    // 2. Tenta extrair de bloco de código genérico ``` ... ```
    else {
        const genericBlockMatch = text.match(/```\s*([\s\S]*?)\s*```/);
        if (genericBlockMatch && genericBlockMatch[1]) {
            jsonString = genericBlockMatch[1];
        } 
        // 3. Fallback: Tenta parsear o texto inteiro se parecer um JSON (começa com { e termina com })
        else if (text.trim().startsWith('{') && text.trim().endsWith('}')) {
            jsonString = text;
        }
    }

    if (jsonString) {
      try {
        const parsed = JSON.parse(jsonString);
        // Validação mínima do schema
        if (parsed.nodes && Array.isArray(parsed.nodes) && parsed.edges && Array.isArray(parsed.edges)) {
          flowData = parsed as FlowSchema;
        }
      } catch (e) {
        console.error("Falha ao parsear JSON do fluxo gerado", e);
      }
    }

    return { text, flowData };

  } catch (error: any) {
    console.error("Gemini API Error:", error);

    let friendlyError = "Erro desconhecido ao conectar com a IA.";

    // Tratamento específico de erros comuns
    const errorMsg = error.message || JSON.stringify(error);

    if (errorMsg.includes('403') || errorMsg.includes('PERMISSION_DENIED')) {
        friendlyError = "⛔ **Acesso Negado (403)**: A API Key fornecida não tem permissão para acessar o modelo `gemini-3-flash-preview`.\n\nDica: Se você estiver usando uma chave antiga de outro projeto, crie uma nova em um projeto com a 'Generative Language API' habilitada.";
    } else if (errorMsg.includes('404') || errorMsg.includes('NOT_FOUND')) {
        friendlyError = "⛔ **Modelo Não Encontrado (404)**: O modelo `gemini-3-flash-preview` não está acessível. A chave pode estar incorreta ou o modelo indisponível na sua região.";
    } else if (errorMsg.includes('429')) {
        friendlyError = "⏳ **Limite de Taxa Excedido (429)**: Você fez muitas requisições em pouco tempo. Tente novamente em alguns instantes.";
    }

    return { text: friendlyError, flowData: undefined };
  }
};

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
import { CREATOR_CREDIT } from '../constants';

// Delay auxiliar para visualização
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const createLog = (nodeId: string, label: string, level: LogEntry['level'], message: string): LogEntry => ({
  id: Math.random().toString(36).substr(2, 9),
  timestamp: new Date().toISOString(),
  nodeId,
  nodeLabel: label,
  level,
  message
});

export class FlowEngine {
  private nodes: FlowNode[];
  private edges: FlowEdge[];
  private setNodes: (nodes: FlowNode[] | ((nodes: FlowNode[]) => FlowNode[])) => void;
  private addLog: (log: LogEntry) => void;
  private onFileGenerated?: (file: GeneratedFile) => void;
  private context: ExecutionContext = {};

  constructor(
    nodes: FlowNode[], 
    edges: FlowEdge[], 
    setNodes: any, 
    addLog: any,
    onFileGenerated?: (file: GeneratedFile) => void
  ) {
    this.nodes = nodes;
    this.edges = edges;
    this.setNodes = setNodes;
    this.addLog = addLog;
    this.onFileGenerated = onFileGenerated;
  }

  private updateNodeStatus(nodeId: string, status: NodeStatus) {
    this.setNodes((nds: FlowNode[]) => 
      nds.map(n => n.id === nodeId ? { ...n, data: { ...n.data, status } } : n)
    );
  }

  private parseConfigJSON(input: any): any {
      if (typeof input === 'object') return input;
      try { return JSON.parse(input); } catch (e) { return {}; }
  }

  // Novo parser robusto de Headers: Aceita JSON ou formato "Key: Value" e faz trim
  private parseHeaders(input: any): Record<string, string> {
      if (!input) return {};
      if (typeof input === 'object') return input;

      try {
          return JSON.parse(input);
      } catch (e) {
          // Fallback: Tenta parsear formato texto (ex: Postman raw headers)
          const headers: Record<string, string> = {};
          const lines = input.toString().split('\n');

          for (const line of lines) {
              const separatorIndex = line.indexOf(':');
              if (separatorIndex > -1) {
                  // Remove quotes extras que o usuário possa ter colado no início/fim da chave ou valor
                  let key = line.substring(0, separatorIndex).trim().replace(/^['"]|['"]$/g, '');
                  let value = line.substring(separatorIndex + 1).trim().replace(/^['"]|['"]$/g, '');

                  if (key) {
                      headers[key] = value;
                  }
              }
          }
          return headers;
      }
  }

  // --- LÓGICA DE FETCH REFORÇADA (5 LAYERS) ---
  private async fetchRealData(url: string, options: any, nodeId: string, label: string): Promise<any> {

      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 45000); 

      // Verifica se nós enviamos autenticação (para saber se o erro é nosso ou do proxy)
      const hasAuth = options.headers && Object.keys(options.headers).some(k => k.toLowerCase() === 'authorization');

      // Helper para processar resposta e EXTRAIR DETALHES DO ERRO
      const processResponse = async (response: Response, sourceName: string) => {
          if (!response.ok) {
              let errorDetails = "";
              try {
                  const text = await response.text();
                  try {
                      const json = JSON.parse(text);
                      errorDetails = json.error?.message || json.message || json.error || text;
                  } catch {
                      errorDetails = text.substring(0, 300);
                  }
              } catch {
                  errorDetails = "Sem detalhes do servidor.";
              }

              if (response.status === 401 || (response.status === 403 && !errorDetails.includes('cors-anywhere'))) {
                  let hint = "";
                  // Detecta se o usuário esqueceu de substituir a chave de exemplo
                  if (errorDetails.includes("YOUR_API_KEY") || errorDetails.includes("Incorrect API key")) {
                       hint = " 💡 DICA: Você está usando uma chave de exemplo ('YOUR_API_KEY'). Edite as configurações deste Node e insira sua chave real.";
                  } else if (errorDetails.toLowerCase().includes("provide an api key")) {
                       hint = " 💡 DICA: O header 'Authorization' parece estar ausente ou incorreto. Verifique se o formato é 'Authorization: Bearer SK-...'";
                  }
                  throw new Error(`AUTH_ERROR: O servidor recusou a conexão (${response.status}) via ${sourceName}. Mensagem da API: "${errorDetails}".${hint}`);
              }
              throw new Error(`${sourceName} Error ${response.status}: ${errorDetails}`);
          }
          return response.json();
      };

      // Helper para tratar erro de proxy: Se o erro for "Chave Ausente" mas nós enviamos a chave,
      // significa que o proxy comeu o header. Então não devemos lançar erro, e sim continuar tentando o próximo proxy.
      const handleProxyError = (e: any, sourceName: string) => {
          if (e.message.includes('AUTH_ERROR')) {
              const msg = e.message.toLowerCase();
              // Se o erro diz que não fornecemos chave, mas hasAuth é true, é culpa do proxy.
              const isMissingKeyError = msg.includes("didn't provide an api key") || msg.includes("provide your api key");

              if (hasAuth && isMissingKeyError) {
                  this.addLog(createLog(nodeId, label, 'WARN', `⚠️ ${sourceName} falhou em repassar a autenticação (Header Stripped). Tentando próxima rota...`));
                  return; // Retorna sem lançar erro, permitindo o código seguir para o próximo try/catch
              }
              throw e; // Se a chave estava errada (Incorrect API Key), lança o erro para parar tudo.
          }
          // Se for outro erro (timeout, network), apenas loga e deixa tentar o próximo
      };

      try {
          // 1. TENTATIVA DIRETA
          this.addLog(createLog(nodeId, label, 'INFO', `📡 [1/5] Tentando conexão direta...`));
          try {
              const response = await fetch(url, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'Direct');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Conexão Direta: OK`));
              return data;
          } catch (e: any) {
              // Direct falhando com auth pode ser CORS do browser bloqueando header. Segue o jogo.
              if (e.message.includes('AUTH_ERROR')) {
                   this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Direct retornou 401. O navegador pode ter bloqueado o Header. Tentando proxies...`));
              } else {
                   this.addLog(createLog(nodeId, label, 'WARN', `⚠️ Direto falhou. Iniciando rota de proxies...`));
              }
          }

          // 2. CORS PROXY IO
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 [2/5] Tentando CorsProxy.io...`));
              const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(url)}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'CorsProxy');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via CorsProxy`));
              return data;
          } catch (e: any) {
              handleProxyError(e, 'CorsProxy');
          }

          // 3. CODE TABS
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 [3/5] Tentando CodeTabs...`));
              const proxyUrl = `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(url)}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'CodeTabs');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via CodeTabs`));
              return data;
          } catch (e: any) {
              handleProxyError(e, 'CodeTabs');
          }

          // 4. THING PROXY
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🔄 [4/5] Tentando ThingProxy...`));
              const proxyUrl = `https://thingproxy.freeboard.io/fetch/${url}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });
              const data = await processResponse(response, 'ThingProxy');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via ThingProxy`));
              return data;
          } catch (e: any) {
              handleProxyError(e, 'ThingProxy');
          }

          // 5. CORS ANYWHERE (ULTIMATE FALLBACK)
          try {
              this.addLog(createLog(nodeId, label, 'INFO', `🛡️ [5/5] Tentando CorsAnywhere (Backup)...`));
              const proxyUrl = `https://cors-anywhere.herokuapp.com/${url}`;
              const response = await fetch(proxyUrl, { ...options, signal: controller.signal });

              if (response.status === 403) {
                   throw new Error("REQUIRES_ACTIVATION");
              }

              const data = await processResponse(response, 'CorsAnywhere');
              clearTimeout(timeoutId);
              this.addLog(createLog(nodeId, label, 'SUCCESS', `✅ Via CorsAnywhere`));
              return data;

          } catch (e: any) {
              if (e.message.includes('AUTH_ERROR')) throw e; // Se CorsAnywhere falhar com Auth, é erro real do usuário
              if (e.message === 'REQUIRES_ACTIVATION' || e.message.includes('See /corsdemo')) {
                  throw new Error(`
                      🔒 BLOQUEIO DE SEGURANÇA DETECTADO.
                      Para usar APIs privadas no navegador:
                      1. Abra uma nova aba: https://cors-anywhere.herokuapp.com/corsdemo
                      2. Clique em "Request temporary access"
                      3. Volte aqui e tente novamente.
                  `);
              }
          }

          // 6. ALL ORIGINS (GET ONLY)
          if (!options.method || options.method === 'GET') {
               try {
                   this.addLog(createLog(nodeId, label, 'INFO', `🔄 [6/6] Tentando AllOrigins (GET)...`));
                   const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`;
                   const response = await fetch(proxyUrl, { signal: controller.signal });
                   const wrapper = await response.json();
                   if (wrapper.contents) {
                       clearTimeout(timeoutId);
                       try { return JSON.parse(wrapper.contents); } catch { return wrapper.contents; }
                   }
               } catch (e) {}
          }

          clearTimeout(timeoutId);
          this.addLog(createLog(nodeId, label, 'ERROR', `❌ Todas as rotas falharam.`));
          throw new Error(`Não foi possível conectar a ${url} através de nenhum proxy.`);

      } catch (finalError: any) {
          clearTimeout(timeoutId);
          throw finalError;
      }
  }

  private async executeNode(node: FlowNode): Promise<boolean> {
    let { type, config, label } = node.data;
    if (!type && node.type) { type = node.type as NodeType; node.data.type = type; }
    if (!label) label = type || 'Node';

    this.updateNodeStatus(node.id, NodeStatus.RUNNING);

    try {
      await wait(800); 

      switch (type) {
        case NodeType.START:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🟢 Início do Fluxo.`));
            break;

        case NodeType.HTTP_REQUEST:
          const method = (config?.method || 'GET').toUpperCase();
          const url = config?.url;

          if (!url) throw new Error("URL é obrigatória.");

          const customHeaders = this.parseHeaders(config?.headers);

          // --- VALIDAÇÃO PRÉ-REQ: Detecta chaves placeholder e chaves vazias ---
          const headerStr = JSON.stringify(customHeaders);
          const INVALID_KEY = 'AIzaSyDmUgmObZ_HsSe9BHdJaUbqgdSud4Qrl6Y';

          if (headerStr.includes('YOUR_API_KEY') || url.includes('YOUR_API_KEY')) {
              throw new Error("CONFIGURAÇÃO NECESSÁRIA: Você está usando uma chave de exemplo ('YOUR_API_KEY'). Edite o Node e insira sua credencial real.");
          }
          if (headerStr.includes(INVALID_KEY) || url.includes(INVALID_KEY)) {
              throw new Error("CHAVE INVÁLIDA DETECTADA: A chave 'AIzaSyDm...' é um exemplo público e não funciona. Use uma chave real.");
          }

          // --- VALIDAÇÃO PRÉ-REQ: Detecta falta de Auth para OpenAI ---
          if (url.includes('api.openai.com') && !customHeaders['Authorization'] && !customHeaders['authorization']) {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Detectada URL da OpenAI sem header 'Authorization'. A requisição provavelmente falhará.`));
          }

          const isBodyMethod = ['POST', 'PUT', 'PATCH'].includes(method);
          const headers: Record<string, string> = { ...customHeaders };
          if (isBodyMethod && !headers['Content-Type']) headers['Content-Type'] = 'application/json';
          const body = isBodyMethod ? JSON.stringify(this.parseConfigJSON(config?.body)) : undefined;

          // Validação extra no corpo da requisição
          if (body && (body.includes('YOUR_API_KEY') || body.includes(INVALID_KEY))) {
             throw new Error("CONFIGURAÇÃO NECESSÁRIA: Corpo da requisição contém chaves de exemplo (YOUR_API_KEY ou AIza...). Edite o payload.");
          }

          // Executa Fetch Seguro
          const responseData = await this.fetchRealData(url, { method, headers, body }, node.id, label);

          // Salva no contexto
          this.context[node.id] = responseData;
          this.context['input'] = responseData; 
          this.context['data'] = responseData; 

          const preview = JSON.stringify(responseData).substring(0, 100) + "...";
          this.addLog(createLog(node.id, label, 'INFO', `📦 Dados recebidos: ${preview}`));
          break;

        case NodeType.IF_CONDITION:
          const conditionStr = config?.condition || 'true';
          let result = true;

          const edgeIn = this.edges.find(e => e.target === node.id);
          const inputData = edgeIn ? this.context[edgeIn.source] : (this.context['input'] || {});

          try {
              const checkCondition = new Function('input', 'data', 'json', `
                  try { return ${conditionStr}; } catch(e) { return false; }
              `);
              result = checkCondition(inputData, inputData, inputData);
              this.addLog(createLog(node.id, label, result ? 'SUCCESS' : 'WARN', `⚖️ Condição (${conditionStr}) => ${result ? 'VERDADEIRO' : 'FALSO'}`));
          } catch (e) { 
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Erro na sintaxe da condição. Continuando fluxo (TRUE).`));
              result = true; 
          }
          this.context[node.id] = result;
          break;

        case NodeType.FILE_SAVE:
          const incomingEdge = this.edges.find(e => e.target === node.id);
          const fileName = config?.fileName || `output-${Date.now()}.txt`;

          let sourceData = incomingEdge ? this.context[incomingEdge.source] : this.context['input'];
          if (typeof sourceData === 'boolean') sourceData = this.context['input'];

          if (sourceData) {
            let contentStr = typeof sourceData === 'object' ? JSON.stringify(sourceData, null, 2) : String(sourceData);
            if (this.onFileGenerated) {
                this.onFileGenerated({
                    id: crypto.randomUUID(),
                    name: fileName,
                    content: contentStr,
                    extension: config?.fileFormat || 'txt',
                    timestamp: Date.now(),
                    nodeId: node.id
                });
                this.addLog(createLog(node.id, label, 'SUCCESS', `💾 Arquivo salvo.`));
            }
          } else {
              this.addLog(createLog(node.id, label, 'WARN', `⚠️ Sem dados para salvar.`));
          }
          break;

        case NodeType.DELAY:
           const ms = config?.ms || 1000;
           this.addLog(createLog(node.id, label, 'INFO', `⏳ Aguardando ${ms}ms...`));
           await wait(ms);
           break;

        case NodeType.LOGGER:
            const edgeInLog = this.edges.find(e => e.target === node.id);
            const dataToLog = edgeInLog ? this.context[edgeInLog.source] : this.context;
            this.addLog(createLog(node.id, label, 'INFO', `📝 Log: ${JSON.stringify(dataToLog, null, 2)}`));
            break;

        case NodeType.WEBHOOK:
            this.addLog(createLog(node.id, label, 'SUCCESS', `🔔 Webhook acionado.`));
            break;

        default:
          break;
      }

      this.updateNodeStatus(node.id, NodeStatus.SUCCESS);
      return true;

    } catch (error: any) {
      console.error(error);
      this.updateNodeStatus(node.id, NodeStatus.ERROR);
      this.addLog(createLog(node.id, label, 'ERROR', `❌ ${error.message}`));
      return false; 
    }
  }

  public async run() {
    this.addLog(createLog('system', 'System', 'INFO', `🚀 --- INICIANDO EXECUÇÃO ---`));
    this.context = {}; 

    this.setNodes((nds: FlowNode[]) => nds.map(n => ({ ...n, data: { ...n.data, status: NodeStatus.IDLE } })));
    await wait(200);

    const startNodes = this.nodes.filter(n => n.data.type === NodeType.START || n.data.type === NodeType.WEBHOOK);
    const queue: FlowNode[] = startNodes.length > 0 ? startNodes : [this.nodes[0]];

    if (queue.length === 0 && this.nodes.length > 0) queue.push(this.nodes[0]);

    while (queue.length > 0) {
      const currentNode = queue.shift();
      if (!currentNode) continue;

      const success = await this.executeNode(currentNode);

      if (success) {
        if (currentNode.data.type === NodeType.IF_CONDITION && this.context[currentNode.id] === false) {
             this.addLog(createLog(currentNode.id, currentNode.data.label, 'WARN', `⚠️ Condição Falsa. Fluxo segue, mas verifique a lógica.`));
        }

        const outgoingEdges = this.edges.filter(e => e.source === currentNode.id);
        for (const edge of outgoingEdges) {
          const nextNode = this.nodes.find(n => n.id === edge.target);
          if (nextNode) {
             queue.push(nextNode);
          }
        }
      } else {
        break;
      }
    }

    this.addLog(createLog('system', 'System', 'INFO', `🏁 Execução Finalizada.`));
  }
}

import { FlowNode, FlowEdge, NodeType, NodeStatus, LogEntry, ExecutionContext, GeneratedFile } from '../types';
