              if (response.status === 401 || (response.status === 403 && !errorDetails.includes('cors-anywhere'))) {
                  let hint = "";
                  // Detecta erros comuns de chave
                  const lowerDetails = errorDetails.toLowerCase();
                  if (lowerDetails.includes("your_api_key") || lowerDetails.includes("sua_chave")) {
                       hint = " 💡 DICA: O servidor recebeu um placeholder em vez de uma chave real. Verifique a configuração.";
                  } else if (lowerDetails.includes("incorrect api key")) {
                       hint = " 💡 DICA: A chave de API enviada foi rejeitada pelo provedor. Verifique se a chave está correta.";
