      };

      // Helper para tratar erro de proxy
      const handleProxyError = (e: any, sourceName: string) => {
          if (e.message.includes('AUTH_ERROR')) {
              const msg = e.message.toLowerCase();
              // Se o erro diz que não fornecemos chave, mas hasAuth é true, é culpa do proxy que removeu o header.
