const STORAGE_KEY = 'flow_architect_projects_v1';
const API_KEY_STORAGE_KEY = 'flow_architect_user_api_key_v1';

export const storageService = {
  getProjects: (): SavedProject[] => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      return stored ? JSON.parse(stored) : [];
    } catch (e) {
      console.error("Erro ao ler projetos:", e);
      return [];
    }
  },

  saveProject: (name: string, nodes: FlowNode[], edges: FlowEdge[], files: GeneratedFile[]): SavedProject => {
    const projects = storageService.getProjects();

    const newProject: SavedProject = {
      id: crypto.randomUUID(),
      name,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      nodes,
      edges,
      files
    };

    const updatedProjects = [newProject, ...projects];
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedProjects));
    return newProject;
  },

  deleteProject: (id: string): void => {
    const projects = storageService.getProjects();
    const filtered = projects.filter(p => p.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
  },

  updateProject: (id: string, nodes: FlowNode[], edges: FlowEdge[], files: GeneratedFile[]): void => {
    const projects = storageService.getProjects();
    const index = projects.findIndex(p => p.id === id);

    if (index !== -1) {
      projects[index] = {
        ...projects[index],
        nodes,
        edges,
        files,
        updatedAt: Date.now()
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    }
  },

  // --- API KEY MANAGEMENT ---
  saveApiKey: (key: string): void => {
    localStorage.setItem(API_KEY_STORAGE_KEY, key.trim());
  },

  getApiKey: (): string | null => {
    return localStorage.getItem(API_KEY_STORAGE_KEY);
  },

  removeApiKey: (): void => {
    localStorage.removeItem(API_KEY_STORAGE_KEY);
  }
};

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { FlowSchema } from '../types';
import { storageService } from './storageService';

// Chave de exemplo pública que causa erro 403 frequente em tutoriais
const INVALID_EXAMPLE_KEY = 'AIzaSyDmUgmObZ_HsSe9BHdJaUbqgdSud4Qrl6Y';

export const generateFlowFromPrompt = async (userPrompt: string): Promise<{ text: string, flowData?: FlowSchema }> => {
  // Prioridade: 1. Chave salva pelo usuário (Storage) | 2. Variável de Ambiente
  const storedKey = storageService.getApiKey();
  const envKey = process.env.API_KEY;
  const activeKey = storedKey || envKey;

  // 1. Verificação de Chave Inválida Conhecida
  if (activeKey === INVALID_EXAMPLE_KEY) {
    return {
      text: "⛔ **Chave de Exemplo Detectada**\n\nA chave que você está usando (`AIzaSyDm...`) é uma chave de demonstração pública e **não funciona** para gerar fluxos.\n\nPor favor, insira uma chave válida nas configurações ou atualize a variável de ambiente.",
      flowData: undefined
    };
  }

  // 2. Verificação de Ausência de Chave
  if (!activeKey) {
    return { 
      text: "⚠️ **Configuração Necessária**: Nenhuma API Key válida detectada. \n\nPara usar o Chat IA, clique no ícone de engrenagem (⚙️) e insira sua API Key do Google Gemini ou configure a variável de ambiente `API_KEY`.", 
      flowData: undefined 
    };
  }

  try {
    // Instancia o cliente dinamicamente com a chave ativa
    const ai = new GoogleGenAI({ apiKey: activeKey });
    const model = 'gemini-3-flash-preview'; 

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        { role: 'user', parts: [{ text: SYSTEM_PROMPT }] },
        { role: 'user', parts: [{ text: `Solicitação do usuário: ${userPrompt}` }] }
      ],
      config: {
        temperature: 0.2, 
      }
    });

    const text = response.text || "Erro ao gerar resposta.";
    let flowData: FlowSchema | undefined;

    // --- ESTRATÉGIA DE PARSING ROBUSTA ---
    let jsonString = '';

    // 1. Tenta extrair de bloco markdown específico ```json ... ```
    const jsonBlockMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonBlockMatch && jsonBlockMatch[1]) {
        jsonString = jsonBlockMatch[1];
    } 
    // 2. Tenta extrair de bloco de código genérico ``` ... ```
    else {
        const genericBlockMatch = text.match(/```\s*([\s\S]*?)\s*```/);
        if (genericBlockMatch && genericBlockMatch[1]) {
            jsonString = genericBlockMatch[1];
        } 
        // 3. Fallback: Tenta parsear o texto inteiro se parecer um JSON (começa com { e termina com })
        else if (text.trim().startsWith('{') && text.trim().endsWith('}')) {
            jsonString = text;
        }
    }

    if (jsonString) {
      try {
        const parsed = JSON.parse(jsonString);
        // Validação mínima do schema
        if (parsed.nodes && Array.isArray(parsed.nodes) && parsed.edges && Array.isArray(parsed.edges)) {
          flowData = parsed as FlowSchema;
        }
      } catch (e) {
        console.error("Falha ao parsear JSON do fluxo gerado", e);
      }
    }

    return { text, flowData };

  } catch (error: any) {
    console.error("Gemini API Error:", error);

    let friendlyError = "Erro desconhecido ao conectar com a IA.";

    // Tratamento específico de erros comuns
    const errorMsg = error.message || JSON.stringify(error);

    if (errorMsg.includes('403') || errorMsg.includes('PERMISSION_DENIED')) {
        friendlyError = "⛔ **Acesso Negado (403)**: A API Key fornecida não tem permissão para acessar o modelo `gemini-3-flash-preview`.\n\nDica: Se você estiver usando uma chave antiga de outro projeto, crie uma nova em um projeto com a 'Generative Language API' habilitada.";
    } else if (errorMsg.includes('404') || errorMsg.includes('NOT_FOUND')) {
        friendlyError = "⛔ **Modelo Não Encontrado (404)**: O modelo `gemini-3-flash-preview` não está acessível. A chave pode estar incorreta ou o modelo indisponível na sua região.";
    } else if (errorMsg.includes('429')) {
        friendlyError = "⏳ **Limite de Taxa Excedido (429)**: Você fez muitas requisições em pouco tempo. Tente novamente em alguns instantes.";
    }

    return { text: friendlyError, flowData: undefined };
  }
};

