        id: Date.now().toString(), 
        timestamp: new Date().toISOString(), 
        level: 'SUCCESS', 
        message: 'Fluxo gerado por IA importado com sucesso. IDs e Posições normalizados.',
        nodeId: 'system',
        nodeLabel: 'System'
      }
