        }));

        const contextString = `
=== CONTEXTO DE DEBUG (O USUÁRIO ESTÁ VENDO ISSO) ===
LOGS DE ERRO/EXECUÇÃO:
${recentLogs || "Nenhum log disponível."}

ESTRUTURA ATUAL:
${JSON.stringify(simplifiedNodes, null, 2)}
=====================================================
`;
        finalPromptParts.push({ text: contextString });
    }

    finalPromptParts.push({ text: `USUÁRIO DIZ: ${userPrompt}` });

    // Prioriza modelos que suportam JSON Mode nativo
    const modelsToTry = [
        'gemini-2.0-flash',      // Excelente para JSON
        'gemini-1.5-flash',      // Muito estável
        'gemini-1.5-pro',        // Mais inteligente
        'gemini-3-flash-preview' // Fallback
    ];

    let response;
    let lastError: any = null;

    for (const model of modelsToTry) {
        try {
            console.log(`[AI] Gerando com modelo: ${model}...`);
            response = await ai.models.generateContent({
                model: model,
                contents: [{ role: 'user', parts: finalPromptParts }],
                config: { 
                    temperature: 0.1, // Baixa temperatura para JSON mais preciso
                    maxOutputTokens: 8000,
                    responseMimeType: 'application/json' // O Segredo: Força saída puramente JSON
                }
            });
            break; 
        } catch (e: any) {
