            if (msg.includes('404') || msg.includes('NOT_FOUND') || msg.includes('403') || msg.includes('503')) {
                console.warn(`Modelo ${model} falhou:`, msg);
                continue;
            }
            continue; 
        }
    }

    if (!response && lastError) throw lastError;

    // Se o modelo obedeceu responseMimeType, o text é JSON puro.
    // Se falhou ou usou um modelo antigo, pode vir texto misturado.
    const text = response?.text || "{}";
    let flowData: FlowSchema | undefined;

    // --- PARSER DE JSON BLINDADO ---
    try {
        let jsonString = text.trim();

        // 1. Se vier envelopado em markdown (fallback), remove
        const jsonBlockMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
        if (jsonBlockMatch && jsonBlockMatch[1]) {
            jsonString = jsonBlockMatch[1];
        } else {
             const simpleBlockMatch = text.match(/```\s*([\s\S]*?)\s*```/);
             if (simpleBlockMatch && simpleBlockMatch[1]) {
                 jsonString = simpleBlockMatch[1];
             }
        }

        // 2. Limpeza de comentários (inválido em JSON padrão mas comum em LLMs)
        // Remove // comentarios
        jsonString = jsonString.replace(/\/\/.*$/gm, "");

        try {
             const parsed = JSON.parse(jsonString);
             // Valida se tem a estrutura mínima de fluxo
             if (parsed.nodes && Array.isArray(parsed.nodes)) {
                flowData = parsed as FlowSchema;
                console.log("Fluxo extraído com sucesso:", flowData.nodes.length, "nodes");
            } else if (parsed.response && parsed.response.nodes) {
                // As vezes a IA aninha dentro de um objeto response
                flowData = parsed.response as FlowSchema;
            }
        } catch (initialParseError) {
            console.error("Parse inicial falhou:", initialParseError);
            // Última tentativa: buscar o objeto JSON bruto entre chaves
            const firstOpen = text.indexOf('{');
            const lastClose = text.lastIndexOf('}');
            if (firstOpen !== -1 && lastClose > firstOpen) {
                const sub = text.substring(firstOpen, lastClose + 1);
                const parsedSub = JSON.parse(sub);
                if (parsedSub.nodes) flowData = parsedSub;
            }
        }

    } catch (e) {
        console.error("Erro fatal ao processar JSON:", e);
    }

    // Define o texto que o usuário vê no chat
    let displayText = text;

    // Se tiver flowData válido, mostramos uma mensagem amigável em vez do JSON cru
    if (flowData) {
        const nodeCount = flowData.nodes.length;
        displayText = `✅ **Fluxo Gerado com Sucesso!**\n\nCriei um automação com **${nodeCount} passos** para você.\n\n*Clique no botão abaixo para carregar no editor.*`;
    } else {
        // Se falhou, tenta ser útil
        if (text.length > 200 && !text.trim().startsWith('{')) {
            // Provavelmente o modelo respondeu com texto explicativo porque não conseguiu gerar JSON
            displayText = text;
        } else {
             displayText = "⚠️ **Erro de Formatação**: A IA tentou gerar o fluxo, mas o formato saiu inválido. Tente reformular o pedido com mais detalhes.";
        }
    }

    return { text: displayText, flowData };

  } catch (error: any) {
    console.error("Fatal Gemini Error:", error);
    let friendlyError = "Erro de conexão com a IA.";

    if (error.message.includes('403')) {
        friendlyError = "⛔ **Erro de Permissão (403)**: Verifique se a API Key é válida e tem permissões.";
    } else if (error.message.includes('404')) {
        friendlyError = "⛔ **Erro de Modelo (404)**: Os modelos AI não estão acessíveis no momento.";
    } else {
        friendlyError = `⛔ **Erro**: ${error.message}`;
    }

    return { text: friendlyError, flowData: undefined };
  }
};

