          </div>
        </main>

        {/* BOTTOM NAV - MOBILE */}
        <nav className="h-16 bg-gray-900 border-t border-gray-800 flex items-center justify-around px-2 shrink-0 z-50 md:hidden pb-[env(safe-area-inset-bottom)]">
